    await executeSearch(location.name);
  };

  const executeSearch = async (locName: string, date?: string) => {
    setLoading(true);
    // Reset seen alerts on new search to allow fresh notifications
    seenAlertsRef.current.clear();

    const result = await fetchAlerts(locName, date);
    setAlerts(result.events);
    setAnalysis(result.analysis);

    // Check for notifications immediately on load if monitoring is on (or auto-enable for high severity?)
    // For now, only notify if monitoring was already enabled, or we can prompt user.
    if (isMonitoring) {
        checkAndNotify(result.events);
    }

    if (!location.name || location.name.startsWith('GPS')) {
       setLocation(prev => ({ ...prev, name: locName }));
    }

    setLoading(false);
    setView(ViewState.DASHBOARD);
  };

  const handleHistorySearch = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!historyLocation) return;

    // Construct date string YYYY-MM-DD
