import { GoogleGenAI, Type, Schema } from "@google/genai";
import { AlertEvent, SeverityLevel, SourceType } from "../types";

const apiKey = process.env.API_KEY || ''; // Injected by environment

const ai = new GoogleGenAI({ apiKey });

const eventSchema: Schema = {
  type: Type.OBJECT,
  properties: {
    events: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING, description: "Título corto del evento en Español" },
          description: { type: Type.STRING, description: "Resumen detallado de lo que está ocurriendo en Español" },
          severity: { type: Type.STRING, enum: [SeverityLevel.CRITICAL, SeverityLevel.WARNING, SeverityLevel.INFO, SeverityLevel.SAFE] },
          category: { type: Type.STRING, description: "Categoría en una palabra: Incendio, Clima, Protesta, Tráfico, Seguridad, Salud, Otro" },
          sourceName: { type: Type.STRING, description: "Nombre de la fuente principal (ej. AEMET, Usuario Twitter, El País)" },
          sourceType: { type: Type.STRING, enum: [SourceType.OFFICIAL, SourceType.NEWS, SourceType.SOCIAL] },
          timeInfo: { type: Type.STRING, description: "Cuándo ocurrió (ej. 'hace 10 min', '1 Ago 14:00')" }
        },
        required: ["title", "description", "severity", "category", "sourceName", "sourceType", "timeInfo"]
      }
    },
    riskAnalysis: { type: Type.STRING, description: "Un breve resumen de 1 oración sobre el nivel general de seguridad para el usuario en Español." }
  },
  required: ["events", "riskAnalysis"]
};

export const fetchAlerts = async (location: string, date?: string): Promise<{ events: AlertEvent[], analysis: string }> => {
  const isHistorical = !!date;

  const systemInstruction = `
    Eres un sistema avanzado de inteligencia de emergencias para España, "Alerta Local".
    Tu trabajo es analizar eventos actuales o pasados en una ubicación específica buscando en la web, noticias y redes sociales.

    Región Objetivo: España.
    Contexto: ${location}.
    Modo: ${isHistorical ? `Archivo Histórico (Fecha: ${date})` : 'Monitoreo en Tiempo Real'}.

    Prioriza:
    1. Fuentes OFICIALES: AEMET (Clima), DGT (Tráfico), Policía, Guardia Civil, 112, Ayuntamientos.
    2. Noticias: Periódicos locales y nacionales (El País, El Mundo, prensa local).
    3. Señales SOCIALES: Tendencias en redes que indiquen disturbios, incendios, accidentes o quejas ciudadanas.

    Clasifica la 'severidad' estrictamente:
    - CRITICAL: Amenaza la vida (Inundaciones, incendios mayores, disturbios violentos, terrorismo).
    - WARNING: Disrupción significativa (Alertas de lluvia intensa, protestas, accidentes de tráfico graves).
    - INFO: Actualizaciones generales, retrasos menores, obras, eventos culturales.
    - SAFE: No se encontraron problemas importantes (indica explícitamente si el área está tranquila).

    IDIOMA: Todo el contenido generado (título, descripción, análisis) DEBE estar en ESPAÑOL.

    Si no se encuentran eventos, devuelve un evento SAFE indicando "No se reportan incidentes significativos".
  `;

  const userPrompt = isHistorical 
    ? `Busca eventos que ocurrieron en ${location} el día ${date}. Busca en archivos de noticias, publicaciones de redes sociales de esa fecha e informes oficiales.`
    : `Encuentra emergencias EN VIVO, advertencias o noticias de última hora en ${location} ahora mismo. Revisa AEMET para el clima, DGT para el tráfico y busca conversaciones recientes en redes sociales sobre incidentes en ${location}.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: userPrompt,
      config: {
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
        responseSchema: eventSchema,
        systemInstruction: systemInstruction,
      },
    });

    const resultText = response.text;
    if (!resultText) throw new Error("No response from AI");

    const parsedData = JSON.parse(resultText);

    // Process grounding chunks to attach real URLs if available
    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];

    const events: AlertEvent[] = parsedData.events.map((evt: any, index: number) => {
      // Attempt to find a relevant link from grounding chunks
      let relevantLink = '';
      if (groundingChunks.length > 0) {
        // Simple heuristic: just assign the web chunk at the corresponding index if it exists, 
        // or the first one if not enough chunks. Ideally, we would match context.
        const chunk = groundingChunks[index % groundingChunks.length];
        if (chunk?.web?.uri) {
            relevantLink = chunk.web.uri;
        }
      }

      // Generate a deterministic ID based on content to allow deduplication across polls
      // Using a simple hash of title + time + location
      const idString = `${evt.title}-${evt.timeInfo}-${location}`;
      let hash = 0;
      for (let i = 0; i < idString.length; i++) {
        const char = idString.charCodeAt(i);
        hash = ((hash << 5) - hash) + char;
        hash = hash & hash; // Convert to 32bit integer
      }
      const deterministicId = `evt-${Math.abs(hash)}`;

      return {
        id: deterministicId,
        title: evt.title,
        description: evt.description,
        location: location,
        timestamp: evt.timeInfo,
        severity: evt.severity as SeverityLevel,
        category: evt.category,
        isHistorical: isHistorical,
        sources: [{
          name: evt.sourceName,
          type: evt.sourceType as SourceType,
          url: relevantLink
        }]
      };
    });

    return {
      events,
      analysis: parsedData.riskAnalysis || "Análisis completo."
    };

  } catch (error) {
    console.error("Gemini API Error:", error);
    return {
      events: [{
        id: 'error-offline',
        title: 'Sistema Desconectado',
        description: 'No se pueden recuperar datos en este momento. Por favor verifique la conexión.',
        location: location,
        timestamp: 'Ahora',
        severity: SeverityLevel.INFO,
        category: 'Sistema',
        sources: []
      }],
      analysis: "El sistema no pudo realizar el análisis."
    };
  }
};

import React from 'react';
import { AlertEvent, SeverityLevel, SourceType } from '../types';
import { AlertTriangle, Shield, Globe, MessageCircle, ExternalLink, Clock, Search } from 'lucide-react';

interface Props {
  event: AlertEvent;
}

const AlertCard: React.FC<Props> = ({ event }) => {
  const getSeverityColors = (level: SeverityLevel) => {
    switch (level) {
      case SeverityLevel.CRITICAL:
        return 'border-l-4 border-l-red-500 bg-red-950/20 text-red-100';
      case SeverityLevel.WARNING:
        return 'border-l-4 border-l-orange-500 bg-orange-950/20 text-orange-100';
      case SeverityLevel.SAFE:
        return 'border-l-4 border-l-green-500 bg-green-950/20 text-green-100';
      default:
        return 'border-l-4 border-l-blue-500 bg-slate-800 text-slate-100';
    }
  };

  const getSourceIcon = (type: SourceType) => {
    switch (type) {
      case SourceType.OFFICIAL: return <Shield className="w-3 h-3 text-blue-400" />;
      case SourceType.SOCIAL: return <MessageCircle className="w-3 h-3 text-purple-400" />;
      default: return <Globe className="w-3 h-3 text-slate-400" />;
    }
  };

  const getVerificationUrl = (sourceName: string, eventTitle: string) => {
    return `https://www.google.com/search?q=${encodeURIComponent(`${sourceName} ${eventTitle} ${event.location}`)}`;
  };

  return (
    <div className={`relative mb-3 p-4 rounded-lg shadow-sm backdrop-blur-sm ${getSeverityColors(event.severity)} transition-all hover:scale-[1.01]`}>
      <div className="flex justify-between items-start mb-2">
        <div className="flex items-center gap-2">
          {event.severity === SeverityLevel.CRITICAL && <AlertTriangle className="w-5 h-5 text-red-500 animate-pulse" />}
          <h3 className="font-bold text-lg leading-tight">{event.title}</h3>
        </div>
        <span className="text-xs font-mono opacity-70 bg-black/20 px-2 py-1 rounded">{event.category.toUpperCase()}</span>
      </div>

      <p className="text-sm opacity-90 mb-3 leading-relaxed">{event.description}</p>

      <div className="flex flex-wrap items-center justify-between gap-2 mt-2 pt-2 border-t border-white/10">
        <div className="flex items-center gap-2 text-xs opacity-70">
          <Clock className="w-3 h-3" />
          <span>{event.timestamp}</span>
        </div>

        <div className="flex gap-2">
            {event.sources.map((source, idx) => {
                const url = source.url || getVerificationUrl(source.name, event.title);
                const isGenerated = !source.url;

                return (
                  <a 
                    key={idx}
                    href={url}
                    target="_blank"
                    rel="noreferrer"
                    title={isGenerated ? "Buscar en Google para verificar" : "Ir a la fuente original"}
                    className="flex items-center gap-1.5 px-2 py-1 rounded-full text-xs font-medium border border-white/10 hover:bg-white/10 transition-colors cursor-pointer group"
                  >
                      {getSourceIcon(source.type)}
                      <span>{source.name}</span>
                      {isGenerated ? (
                          <Search className="w-2.5 h-2.5 opacity-50 group-hover:opacity-100" />
                      ) : (
                          <ExternalLink className="w-2.5 h-2.5 opacity-50 group-hover:opacity-100" />
                      )}
                  </a>
                );
            })}
        </div>
      </div>
    </div>
  );
};

export default AlertCard;

import React from 'react';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip } from 'recharts';
import { AlertEvent, SeverityLevel } from '../types';

interface Props {
  events: AlertEvent[];
}

const StatsChart: React.FC<Props> = ({ events }) => {
  if (events.length === 0) return null;

  const data = [
    { name: 'Crítico', value: events.filter(e => e.severity === SeverityLevel.CRITICAL).length, fill: '#ef4444' },
    { name: 'Aviso', value: events.filter(e => e.severity === SeverityLevel.WARNING).length, fill: '#f97316' },
    { name: 'Info', value: events.filter(e => e.severity === SeverityLevel.INFO).length, fill: '#3b82f6' },
    { name: 'Seguro', value: events.filter(e => e.severity === SeverityLevel.SAFE).length, fill: '#22c55e' },
  ].filter(d => d.value > 0);

  return (
    <div className="h-48 w-full bg-slate-900/50 rounded-xl p-4 mb-4 border border-slate-800">
      <h4 className="text-xs text-slate-400 uppercase tracking-widest font-semibold mb-2 text-center">Distribución de Amenazas</h4>
      <ResponsiveContainer width="100%" height="100%">
        <PieChart>
          <Pie
            data={data}
            cx="50%"
            cy="50%"
            innerRadius={40}
            outerRadius={60}
            paddingAngle={5}
            dataKey="value"
          >
            {data.map((entry, index) => (
              <Cell key={`cell-${index}`} fill={entry.fill} stroke="rgba(0,0,0,0.5)" strokeWidth={2} />
            ))}
          </Pie>
          <Tooltip 
            contentStyle={{ backgroundColor: '#1e293b', borderColor: '#334155', borderRadius: '8px', fontSize: '12px' }}
            itemStyle={{ color: '#fff' }}
          />
        </PieChart>
      </ResponsiveContainer>
    </div>
  );
};

export default StatsChart;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { MapPin, Navigation, Search, History, AlertOctagon, RotateCw, Loader2, Bell, BellOff, Calendar } from 'lucide-react';
import { AlertEvent, UserLocation, SeverityLevel } from './types';
import { fetchAlerts } from './services/geminiService';
import AlertCard from './components/AlertCard';
import StatsChart from './components/StatsChart';

enum ViewState {
  ONBOARDING,
  DASHBOARD,
  HISTORY
}

export default function App() {
  const [view, setView] = useState<ViewState>(ViewState.ONBOARDING);
  const [location, setLocation] = useState<UserLocation>({ name: '', isGPS: false });
  const [alerts, setAlerts] = useState<AlertEvent[]>([]);
  const [analysis, setAnalysis] = useState<string>('');
  const [loading, setLoading] = useState(false);

  // History Mode State - Active query
  const [historyDate, setHistoryDate] = useState<string>('');

  // History Form State
  const [historyLocation, setHistoryLocation] = useState<string>('');
  const [formDay, setFormDay] = useState<number>(new Date().getDate());
  const [formMonth, setFormMonth] = useState<number>(new Date().getMonth()); // 0-11
  const [formYear, setFormYear] = useState<number>(new Date().getFullYear());

  // Notification & Real-time State
  const [isMonitoring, setIsMonitoring] = useState(false);
  const [permission, setPermission] = useState<NotificationPermission>('default');
  const seenAlertsRef = useRef<Set<string>>(new Set());

  useEffect(() => {
    if ('Notification' in window) {
      setPermission(Notification.permission);
    }
  }, []);

  const requestNotificationPermission = async () => {
    if (!('Notification' in window)) {
      alert('Este navegador no soporta notificaciones.');
      return;
    }
    const result = await Notification.requestPermission();
    setPermission(result);
    if (result === 'granted') {
      setIsMonitoring(true);
      // Send a test notification
      new Notification('Alertas Activas', {
        body: `Monitorización en tiempo real activada para ${location.name}.`,
        icon: '/favicon.ico'
      });
    }
  };

  const toggleMonitoring = () => {
    if (isMonitoring) {
      setIsMonitoring(false);
    } else {
      if (permission === 'granted') {
        setIsMonitoring(true);
      } else {
        requestNotificationPermission();
      }
    }
  };

  // Check for critical alerts and notify
  const checkAndNotify = (newAlerts: AlertEvent[]) => {
    if (permission !== 'granted' || !isMonitoring) return;

    newAlerts.forEach(alert => {
      // Only notify for Critical or Warning events that we haven't seen yet
      if ((alert.severity === SeverityLevel.CRITICAL || alert.severity === SeverityLevel.WARNING) && 
          !seenAlertsRef.current.has(alert.id)) {

        // Add to seen set
        seenAlertsRef.current.add(alert.id);

        // Dispatch Notification
        new Notification(`⚠️ ${alert.severity}: ${alert.title}`, {
          body: alert.description,
          tag: alert.id, // Prevent duplicate notifications on some systems
          requireInteraction: alert.severity === SeverityLevel.CRITICAL
        });
      }
    });
  };

  // Background Polling Effect
  useEffect(() => {
    if (view !== ViewState.DASHBOARD || historyDate || !isMonitoring || !location.name) return;

    const intervalId = setInterval(async () => {
      console.log("Polling for updates...");
      try {
        // Silent fetch - do not set main loading state to avoid UI flicker
        const result = await fetchAlerts(location.name);
        setAlerts(result.events);
        setAnalysis(result.analysis);
        checkAndNotify(result.events);
      } catch (e) {
        console.error("Background polling failed", e);
      }
    }, 60000); // Check every 60 seconds

    return () => clearInterval(intervalId);
  }, [view, historyDate, isMonitoring, location.name, permission]);


  const handleGPSLocation = () => {
    setLoading(true);
    if ('geolocation' in navigator) {
      navigator.geolocation.getCurrentPosition(
        async (position) => {
          const lat = position.coords.latitude.toFixed(4);
          const lng = position.coords.longitude.toFixed(4);

          setLocation({ lat: position.coords.latitude, lng: position.coords.longitude, name: `GPS: ${lat}, ${lng}`, isGPS: true });
          await executeSearch(`Coordinates ${lat}, ${lng} Spain`);
        },
        (error) => {
          console.error("GPS Error", error);
          setLoading(false);
          alert("No se pudo obtener el GPS. Por favor introduzca la ubicación manualmente.");
        }
      );
    } else {
      setLoading(false);
      alert("Geolocalización no soportada.");
    }
  };

  const handleManualLocation = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!location.name) return;
    await executeSearch(location.name);
  };

  const executeSearch = async (locName: string, date?: string) => {
    setLoading(true);
    // Reset seen alerts on new search to allow fresh notifications
    seenAlertsRef.current.clear();

    const result = await fetchAlerts(locName, date);
    setAlerts(result.events);
    setAnalysis(result.analysis);

    // Check for notifications immediately on load if monitoring is on (or auto-enable for high severity?)
    // For now, only notify if monitoring was already enabled, or we can prompt user.
    if (isMonitoring) {
        checkAndNotify(result.events);
    }

    if (!location.name || location.name.startsWith('GPS')) {
       setLocation(prev => ({ ...prev, name: locName }));
    }

    setLoading(false);
    setView(ViewState.DASHBOARD);
  };

  const handleHistorySearch = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!historyLocation) return;

    // Construct date string YYYY-MM-DD
    // Ensure month and day are 2 digits
    const mm = (formMonth + 1).toString().padStart(2, '0');
    const dd = formDay.toString().padStart(2, '0');
    const dateStr = `${formYear}-${mm}-${dd}`;

    setHistoryDate(dateStr);

    setLoading(true);
    const result = await fetchAlerts(historyLocation, dateStr);
    setAlerts(result.events);
    setAnalysis(result.analysis);
    setLocation({ name: historyLocation, isGPS: false });
    setIsMonitoring(false); // Disable monitoring for history
    setView(ViewState.DASHBOARD); 
    setLoading(false);
  };

  // Helper arrays for date selectors
  const months = [
    "Enero", "Febrero", "Marzo", "Abril", "Mayo", "Junio", 
    "Julio", "Agosto", "Septiembre", "Octubre", "Noviembre", "Diciembre"
  ];
  const currentYear = new Date().getFullYear();
  const years = Array.from({length: 30}, (_, i) => currentYear - i);
  // Calculate days in selected month
  const daysInMonth = new Date(formYear, formMonth + 1, 0).getDate();
  const days = Array.from({length: daysInMonth}, (_, i) => i + 1);

  // Onboarding View
  const renderOnboarding = () => (
    <div className="flex flex-col items-center justify-center min-h-screen p-6 bg-slate-950 relative overflow-hidden">
      {/* Background Decor */}
      <div className="absolute top-0 left-0 w-full h-full overflow-hidden pointer-events-none">
         <div className="absolute top-[-10%] left-[-10%] w-[50%] h-[50%] bg-emergency-500/10 rounded-full blur-[100px]" />
         <div className="absolute bottom-[-10%] right-[-10%] w-[50%] h-[50%] bg-blue-500/10 rounded-full blur-[100px]" />
      </div>

      <div className="z-10 w-full max-w-md space-y-8 text-center">
        <div className="flex flex-col items-center gap-4">
          <div className="w-20 h-20 bg-slate-900 rounded-2xl flex items-center justify-center shadow-2xl shadow-emergency-900/20 border border-slate-800">
             <AlertOctagon className="w-10 h-10 text-emergency-500" />
          </div>
          <h1 className="text-4xl font-black tracking-tighter text-transparent bg-clip-text bg-gradient-to-r from-white to-slate-400">
            ALERTA ESPAÑA
          </h1>
          <p className="text-slate-400 text-lg">
            Monitor de emergencias en tiempo real.
          </p>
        </div>

        <div className="w-full bg-slate-900/50 backdrop-blur-md p-6 rounded-2xl border border-slate-800 shadow-xl">
          <button 
            onClick={handleGPSLocation}
            disabled={loading}
            className="w-full py-4 bg-blue-600 hover:bg-blue-500 text-white rounded-xl font-bold flex items-center justify-center gap-2 transition-all active:scale-95 mb-4 group"
          >
            {loading ? <Loader2 className="animate-spin" /> : <Navigation className="w-5 h-5 group-hover:animate-pulse" />}
            Usar mi ubicación actual
          </button>

          <div className="relative flex py-2 items-center">
            <div className="flex-grow border-t border-slate-800"></div>
            <span className="flex-shrink mx-4 text-slate-500 text-xs uppercase tracking-widest">o busca tu ciudad</span>
            <div className="flex-grow border-t border-slate-800"></div>
          </div>

          <form onSubmit={handleManualLocation} className="mt-4 flex gap-2">
            <input 
              type="text" 
              placeholder="Ej: Toledo, Valencia, Madrid..." 
              className="flex-1 bg-slate-950 border border-slate-700 rounded-xl px-4 py-3 text-white focus:outline-none focus:border-blue-500 transition-colors"
              value={location.name}
              onChange={(e) => setLocation({ ...location, name: e.target.value })}
            />
            <button 
              type="submit"
              disabled={loading || !location.name}
              className="bg-slate-800 hover:bg-slate-700 text-white p-3 rounded-xl transition-colors border border-slate-700 disabled:opacity-50"
            >
              {loading ? <Loader2 className="animate-spin w-5 h-5" /> : <Search className="w-5 h-5" />}
            </button>
          </form>

          <button 
            onClick={() => setView(ViewState.HISTORY)}
            className="w-full mt-4 py-2 text-xs text-slate-500 hover:text-slate-300 flex items-center justify-center gap-1 transition-colors"
          >
            <History className="w-3 h-3" />
            Búsqueda histórica
          </button>
        </div>
      </div>
    </div>
  );

  // History Search View
  const renderHistory = () => (
    <div className="flex flex-col items-center justify-center min-h-screen p-6 bg-slate-950">
      <div className="w-full max-w-md bg-slate-900/80 p-6 rounded-2xl border border-slate-800 shadow-xl">
        <div className="flex items-center gap-2 mb-6 text-slate-300 cursor-pointer" onClick={() => setView(ViewState.ONBOARDING)}>
          <Calendar className="w-6 h-6 text-purple-500" />
          <span className="text-xl font-bold">Archivo Histórico</span>
        </div>

        <form onSubmit={handleHistorySearch} className="space-y-4">
          <div>
            <label className="text-xs text-slate-400 uppercase font-bold mb-1 block">Ubicación</label>
            <input 
              type="text"
              required
              value={historyLocation}
              onChange={(e) => setHistoryLocation(e.target.value)}
              placeholder="Ciudad o región"
              className="w-full bg-slate-950 border border-slate-700 rounded-lg px-4 py-3 text-white focus:border-purple-500 focus:outline-none transition-colors"
            />
          </div>
          <div>
            <label className="text-xs text-slate-400 uppercase font-bold mb-1 block">Fecha del Evento</label>
            <div className="grid grid-cols-3 gap-2">
                {/* Day */}
                <div className="relative">
                   <select 
                      value={formDay} 
                      onChange={(e) => setFormDay(Number(e.target.value))}
                      className="w-full bg-slate-950 border border-slate-700 rounded-lg px-2 py-3 text-white appearance-none text-center focus:border-purple-500 focus:outline-none"
                   >
                     {days.map(d => <option key={d} value={d}>{d}</option>)}
                   </select>
                   <span className="absolute right-2 top-1/2 -translate-y-1/2 pointer-events-none text-slate-500 text-xs">Día</span>
                </div>

                {/* Month */}
                <div className="relative">
                    <select 
                        value={formMonth} 
                        onChange={(e) => {
                            const newMonth = Number(e.target.value);
                            setFormMonth(newMonth);
                            // Adjust day if new month has fewer days
                            const maxDay = new Date(formYear, newMonth + 1, 0).getDate();
                            if (formDay > maxDay) setFormDay(maxDay);
                        }}
                        className="w-full bg-slate-950 border border-slate-700 rounded-lg px-2 py-3 text-white appearance-none text-center focus:border-purple-500 focus:outline-none"
                    >
                        {months.map((m, idx) => <option key={idx} value={idx}>{m.substring(0,3)}</option>)}
                    </select>
                     <span className="absolute right-2 top-1/2 -translate-y-1/2 pointer-events-none text-slate-500 text-xs">Mes</span>
                </div>

                {/* Year */}
                 <div className="relative">
                    <select 
                        value={formYear} 
                        onChange={(e) => setFormYear(Number(e.target.value))}
                        className="w-full bg-slate-950 border border-slate-700 rounded-lg px-2 py-3 text-white appearance-none text-center focus:border-purple-500 focus:outline-none"
                    >
                        {years.map(y => <option key={y} value={y}>{y}</option>)}
                    </select>
                     <span className="absolute right-2 top-1/2 -translate-y-1/2 pointer-events-none text-slate-500 text-xs">Año</span>
                 </div>
            </div>
            <p className="text-xs text-slate-500 mt-2 text-center">
               Selecciona la fecha exacta del evento pasado.
            </p>
          </div>
          <button 
            type="submit"
            disabled={loading}
            className="w-full bg-purple-600 hover:bg-purple-500 text-white py-3 rounded-lg font-bold flex items-center justify-center gap-2 transition-all active:scale-95"
          >
             {loading ? <Loader2 className="animate-spin" /> : <Search className="w-4 h-4" />}
             Buscar en el pasado
          </button>
        </form>
        <button onClick={() => setView(ViewState.ONBOARDING)} className="mt-4 text-sm text-slate-500 w-full text-center hover:text-white">Cancelar</button>
      </div>
    </div>
  );

  // Dashboard View
  const renderDashboard = () => (
    <div className="min-h-screen bg-slate-950 flex flex-col">
      {/* Header */}
      <header className="sticky top-0 z-50 bg-slate-900/90 backdrop-blur-md border-b border-slate-800 px-4 py-3 shadow-lg">
        <div className="flex justify-between items-center max-w-2xl mx-auto">
          <div className="flex items-center gap-2" onClick={() => setView(ViewState.ONBOARDING)}>
            <MapPin className="text-emergency-500 w-5 h-5" />
            <h2 className="font-bold text-lg text-white truncate max-w-[150px] sm:max-w-none capitalize">{location.name}</h2>
          </div>
          <div className="flex gap-2">
            {!historyDate && (
               <button
                  onClick={toggleMonitoring}
                  className={`p-2 rounded-full transition-all ${isMonitoring ? 'bg-emergency-500/20 text-emergency-500 ring-2 ring-emergency-500/50' : 'bg-slate-800 text-slate-400 hover:text-white'}`}
                  title={isMonitoring ? "Monitorización activada (Notificaciones ON)" : "Activar monitorización"}
               >
                  {isMonitoring ? <Bell className="w-5 h-5 animate-pulse" /> : <BellOff className="w-5 h-5" />}
               </button>
            )}
            <button 
               onClick={() => executeSearch(location.name, historyDate || undefined)}
               className="p-2 bg-slate-800 rounded-full text-slate-300 hover:text-white hover:bg-slate-700 transition-all"
            >
              <RotateCw className={`w-5 h-5 ${loading ? 'animate-spin' : ''}`} />
            </button>
             <button 
               onClick={() => {
                   setHistoryDate(''); 
                   setHistoryLocation('');
                   setView(ViewState.ONBOARDING);
                   setIsMonitoring(false);
               }}
               className="p-2 bg-slate-800 rounded-full text-slate-300 hover:text-white hover:bg-slate-700 transition-all"
            >
              <Search className="w-5 h-5" />
            </button>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-1 p-4 max-w-2xl mx-auto w-full overflow-y-auto no-scrollbar pb-24">

        {loading ? (
            <div className="flex flex-col items-center justify-center h-64 space-y-4 opacity-50">
                <Loader2 className="w-10 h-10 animate-spin text-blue-500" />
                <p className="animate-pulse">Analizando redes sociales y fuentes oficiales...</p>
            </div>
        ) : (
            <>
                {/* Monitor Status Banner */}
                {isMonitoring && !historyDate && (
                   <div className="bg-emergency-900/30 border border-emergency-500/30 rounded-lg p-3 mb-4 flex items-center justify-between animate-pulse">
                      <div className="flex items-center gap-2 text-emergency-200">
                         <span className="relative flex h-3 w-3">
                           <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-red-400 opacity-75"></span>
                           <span className="relative inline-flex rounded-full h-3 w-3 bg-red-500"></span>
                         </span>
                         <span className="text-xs font-bold uppercase tracking-wider">Monitorizando en tiempo real</span>
                      </div>
                      <span className="text-xs text-emergency-200/50 font-mono">Actualiza cada 60s</span>
                   </div>
                )}

                {/* Historical Banner */}
                {historyDate && (
                     <div className="bg-purple-900/30 border border-purple-500/30 rounded-lg p-3 mb-4 flex items-center gap-3">
                        <Calendar className="w-5 h-5 text-purple-400" />
                        <div>
                            <div className="text-purple-200 text-sm font-bold">Archivo Histórico</div>
                            <div className="text-purple-300/70 text-xs">Mostrando eventos del {historyDate}</div>
                        </div>
                     </div>
                )}

                {/* AI Summary */}
                <div className="bg-gradient-to-r from-slate-900 to-slate-800 p-4 rounded-xl border border-slate-700 mb-6 relative overflow-hidden">
                    <div className="absolute top-0 right-0 w-20 h-20 bg-white/5 rounded-full blur-2xl transform translate-x-10 -translate-y-10"></div>
                    <h3 className="text-xs font-bold text-blue-400 uppercase tracking-wider mb-2 flex items-center gap-1">
                        <AlertOctagon className="w-3 h-3" />
                        Informe de Situación
                    </h3>
                    <p className="text-sm leading-relaxed text-slate-200">{analysis}</p>
                </div>

                <StatsChart events={alerts} />

                <h3 className="text-lg font-bold text-white mb-3">Eventos Detectados ({alerts.length})</h3>
                <div className="space-y-4">
                    {alerts.map(event => (
                        <AlertCard key={event.id} event={event} />
                    ))}
                    {alerts.length === 0 && (
                        <div className="text-center py-10 text-slate-500 border border-dashed border-slate-800 rounded-xl">
                            No se encontraron eventos significativos.
                        </div>
                    )}
                </div>
            </>
        )}
      </main>

      {/* Sticky Legend/Footer */}
      <div className="fixed bottom-0 w-full bg-slate-900 border-t border-slate-800 p-3 text-xs text-slate-400 flex justify-center gap-4 z-40 max-w-2xl left-1/2 -translate-x-1/2 rounded-t-xl">
          <div className="flex items-center gap-1"><span className="w-2 h-2 rounded-full bg-red-500"></span> Crítico</div>
          <div className="flex items-center gap-1"><span className="w-2 h-2 rounded-full bg-orange-500"></span> Aviso</div>
          <div className="flex items-center gap-1"><span className="w-2 h-2 rounded-full bg-blue-500"></span> Oficial</div>
          <div className="flex items-center gap-1"><span className="w-2 h-2 rounded-full bg-purple-500"></span> Social</div>
      </div>
    </div>
  );

  return (
    <>
      {view === ViewState.ONBOARDING && renderOnboarding()}
      {view === ViewState.HISTORY && renderHistory()}
      {view === ViewState.DASHBOARD && renderDashboard()}
    </>
  );
}

