                <div className="flex items-center gap-1.5 text-xs text-slate-500 dark:text-slate-400 whitespace-nowrap bg-slate-100 dark:bg-black/30 px-2 py-1 rounded-md border border-slate-200 dark:border-white/5">
                    <Clock className="w-3 h-3" />
                    <span>{event.timestamp}</span>
                </div>
            </div>

            <div className="flex flex-wrap items-center gap-2 mt-2">
                <span className={`px-2 py-0.5 rounded text-[10px] font-bold uppercase tracking-wider border ${styles.badge}`}>
                    {event.category}
                </span>
                {event.location && (
                     <span className="flex items-center gap-1 text-[10px] text-slate-500 dark:text-slate-400 px-2 py-0.5 rounded border border-slate-200 dark:border-white/5 bg-slate-100 dark:bg-black/10">
                        <MapPin className="w-3 h-3" />
                        {event.location}
                    </span>
                )}
            </div>
        </div>
      </div>

      {/* Body */}
      <div className="mt-4 pl-0 sm:pl-[3.5rem]"> {/* Align with text start on larger screens */}
        <p className="text-sm text-slate-600 dark:text-slate-300 leading-relaxed font-light">
            {event.description}
        </p>
      </div>

      {/* Footer / Sources */}
      <div className="mt-4 pt-3 pl-0 sm:pl-[3.5rem] border-t border-slate-200 dark:border-white/5 flex flex-wrap gap-2 items-center">
        <span className="text-[10px] uppercase tracking-wider text-slate-500 font-semibold mr-1">Fuentes:</span>
        {event.sources.map((source, idx) => {
            const url = source.url || getVerificationUrl(source.name, event.title);
            const isGenerated = !source.url;

            // Source specific styles
            let sourceStyle = "bg-slate-100 text-slate-600 hover:bg-slate-200 border-slate-200 dark:bg-slate-800 dark:text-slate-300 dark:hover:bg-slate-700 dark:border-slate-700";
            if (source.type === SourceType.OFFICIAL) sourceStyle = "bg-blue-50 text-blue-700 hover:bg-blue-100 border-blue-200 dark:bg-blue-900/30 dark:text-blue-200 dark:hover:bg-blue-900/50 dark:border-blue-800/50";
            if (source.type === SourceType.SOCIAL) sourceStyle = "bg-purple-50 text-purple-700 hover:bg-purple-100 border-purple-200 dark:bg-purple-900/30 dark:text-purple-200 dark:hover:bg-purple-900/50 dark:border-purple-800/50";

            return (
              <a 
                key={idx}
                href={url}
                target="_blank"
                rel="noreferrer"
                className={`flex items-center gap-1.5 px-2.5 py-1 rounded-md text-xs font-medium border transition-colors cursor-pointer group/link ${sourceStyle}`}
              >
                  {getSourceIcon(source.type)}
                  <span>{source.name}</span>
                  {isGenerated ? (
                      <Search className="w-2.5 h-2.5 opacity-50 group-hover/link:opacity-100" />
                  ) : (
                      <ExternalLink className="w-2.5 h-2.5 opacity-50 group-hover/link:opacity-100" />
                  )}
              </a>
            );
        })}
      </div>
    </div>
  );
};

export default AlertCard;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { MapPin, Navigation, Search, History, AlertOctagon, RotateCw, Loader2, Bell, BellOff, Calendar, Filter, Sun, Moon, Info, ShieldAlert } from 'lucide-react';
import { AlertEvent, UserLocation, SeverityLevel } from './types';
import { fetchAlerts } from './services/geminiService';
import AlertCard from './components/AlertCard';
import StatsChart from './components/StatsChart';

enum ViewState {
  ONBOARDING,
  DASHBOARD,
  HISTORY
}

export default function App() {
  const [view, setView] = useState<ViewState>(ViewState.ONBOARDING);
  const [location, setLocation] = useState<UserLocation>({ name: '', isGPS: false });
  const [alerts, setAlerts] = useState<AlertEvent[]>([]);
  const [analysis, setAnalysis] = useState<string>('');
  const [loading, setLoading] = useState(false);
  const [radius, setRadius] = useState<number>(10); // Default 10km

  // Theme State
  const [theme, setTheme] = useState<'light' | 'dark'>(() => {
    if (typeof window !== 'undefined') {
        const saved = localStorage.getItem('theme');
        return (saved === 'light' || saved === 'dark') ? saved : 'dark';
    }
    return 'dark';
  });

  // Apply Theme
  useEffect(() => {
    const root = window.document.documentElement;
    if (theme === 'dark') {
        root.classList.add('dark');
    } else {
        root.classList.remove('dark');
    }
    localStorage.setItem('theme', theme);
  }, [theme]);

  const toggleTheme = () => setTheme(prev => prev === 'dark' ? 'light' : 'dark');

  // History Mode State - Active query
  const [historyDate, setHistoryDate] = useState<string>('');
  const [activeHistoryCategory, setActiveHistoryCategory] = useState<string>('');

  // History Form State
  const [historyLocation, setHistoryLocation] = useState<string>('');
  const [formDay, setFormDay] = useState<number>(new Date().getDate());
  const [formMonth, setFormMonth] = useState<number>(new Date().getMonth()); // 0-11
  const [formYear, setFormYear] = useState<number>(new Date().getFullYear());
  const [formCategory, setFormCategory] = useState<string>('TODAS');

  // Notification & Real-time State
  const [isMonitoring, setIsMonitoring] = useState(false);
  const [permission, setPermission] = useState<NotificationPermission>('default');
  const seenAlertsRef = useRef<Set<string>>(new Set());

  useEffect(() => {
    if ('Notification' in window) {
      setPermission(Notification.permission);
    }
  }, []);

  const requestNotificationPermission = async () => {
    if (!('Notification' in window)) {
      alert('Este navegador no soporta notificaciones.');
      return;
    }
    const result = await Notification.requestPermission();
    setPermission(result);
    if (result === 'granted') {
      setIsMonitoring(true);
      // Send a test notification
      new Notification('Alertas Activas', {
        body: `Monitorización en tiempo real activada para ${location.name}.`,
        icon: '/favicon.ico'
      });
    }
  };

  const toggleMonitoring = () => {
    if (isMonitoring) {
      setIsMonitoring(false);
    } else {
      if (permission === 'granted') {
        setIsMonitoring(true);
      } else {
        requestNotificationPermission();
      }
    }
  };

  // Check for critical alerts and notify
  const checkAndNotify = (newAlerts: AlertEvent[]) => {
    if (permission !== 'granted' || !isMonitoring) return;

    newAlerts.forEach(alert => {
      // Only notify for Critical or Warning events that we haven't seen yet
      if ((alert.severity === SeverityLevel.CRITICAL || alert.severity === SeverityLevel.WARNING) && 
          !seenAlertsRef.current.has(alert.id)) {

        // Add to seen set
        seenAlertsRef.current.add(alert.id);

        // Dispatch Notification
        new Notification(`⚠️ ${alert.severity}: ${alert.title}`, {
          body: alert.description,
          tag: alert.id, // Prevent duplicate notifications on some systems
          requireInteraction: alert.severity === SeverityLevel.CRITICAL
        });
      }
    });
  };

  // Background Polling Effect
  useEffect(() => {
    if (view !== ViewState.DASHBOARD || historyDate || !isMonitoring || !location.name) return;

    const intervalId = setInterval(async () => {
      console.log("Polling for updates...");
      try {
        const result = await fetchAlerts(location.name, undefined, radius);
        setAlerts(result.events);
        setAnalysis(result.analysis);
        checkAndNotify(result.events);
      } catch (e) {
        console.error("Background polling failed", e);
      }
    }, 60000); // Check every 60 seconds

    return () => clearInterval(intervalId);
  }, [view, historyDate, isMonitoring, location.name, permission, radius]);


  const handleGPSLocation = () => {
    setLoading(true);
    if ('geolocation' in navigator) {
      navigator.geolocation.getCurrentPosition(
        async (position) => {
          const lat = position.coords.latitude.toFixed(4);
          const lng = position.coords.longitude.toFixed(4);

          setLocation({ lat: position.coords.latitude, lng: position.coords.longitude, name: `GPS: ${lat}, ${lng}`, isGPS: true });
          await executeSearch(`Coordenadas ${lat}, ${lng} España`, undefined, radius);
        },
        (error) => {
          console.error("GPS Error", error);
          setLoading(false);
          alert("No se pudo obtener el GPS. Por favor introduzca la ubicación manualmente.");
        }
      );
    } else {
      setLoading(false);
      alert("Geolocalización no soportada.");
    }
  };

  const handleHistoryGPS = () => {
    setLoading(true);
    if ('geolocation' in navigator) {
      navigator.geolocation.getCurrentPosition(
        (position) => {
          const lat = position.coords.latitude.toFixed(4);
          const lng = position.coords.longitude.toFixed(4);
          setHistoryLocation(`Coordenadas GPS: ${lat}, ${lng}`);
          setLoading(false);
        },
        (error) => {
          console.error("GPS Error", error);
          setLoading(false);
          alert("No se pudo obtener el GPS.");
        }
      );
    } else {
      setLoading(false);
      alert("Geolocalización no soportada.");
    }
  };

  const handleManualLocation = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!location.name) return;
    await executeSearch(location.name);
  };

  const executeSearch = async (locName: string, date?: string, searchRadius?: number, category?: string) => {
    setLoading(true);
    seenAlertsRef.current.clear();

    const effectiveRadius = searchRadius || radius;

    const result = await fetchAlerts(locName, date, effectiveRadius, category);
    setAlerts(result.events);
    setAnalysis(result.analysis);

    if (isMonitoring) {
        checkAndNotify(result.events);
    }

    if (!location.name || location.name.startsWith('GPS')) {
       setLocation(prev => ({ ...prev, name: locName }));
    }

    setLoading(false);
    setView(ViewState.DASHBOARD);
  };

  const handleHistorySearch = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!historyLocation) return;

    const mm = (formMonth + 1).toString().padStart(2, '0');
    const dd = formDay.toString().padStart(2, '0');
    const dateStr = `${formYear}-${mm}-${dd}`;

    setHistoryDate(dateStr);
    setActiveHistoryCategory(formCategory);

    setLoading(true);
    const result = await fetchAlerts(historyLocation, dateStr, undefined, formCategory);
    setAlerts(result.events);
    setAnalysis(result.analysis);
    setLocation({ name: historyLocation, isGPS: false });
    setIsMonitoring(false);
    setView(ViewState.DASHBOARD); 
    setLoading(false);
  };

  const months = [
    "Enero", "Febrero", "Marzo", "Abril", "Mayo", "Junio", 
    "Julio", "Agosto", "Septiembre", "Octubre", "Noviembre", "Diciembre"
  ];
  const currentYear = new Date().getFullYear();
  const years = Array.from({length: 30}, (_, i) => currentYear - i);
  const daysInMonth = new Date(formYear, formMonth + 1, 0).getDate();
  const days = Array.from({length: daysInMonth}, (_, i) => i + 1);

  const categories = [
    "TODAS", "Emergencias 112", "ES-Alert", "Incendios", "Clima / AEMET", "Tráfico / DGT", "Seguridad Ciudadana"
  ];

  const renderOnboarding = () => (
    <div className="flex flex-col items-center justify-center min-h-screen p-6 bg-slate-50 dark:bg-slate-950 relative overflow-hidden transition-colors duration-300">
      <div className="absolute top-0 left-0 w-full h-full overflow-hidden pointer-events-none opacity-50 dark:opacity-100">
         <div className="absolute top-[-10%] left-[-10%] w-[50%] h-[50%] bg-emergency-500/10 rounded-full blur-[100px]" />
         <div className="absolute bottom-[-10%] right-[-10%] w-[50%] h-[50%] bg-blue-500/10 rounded-full blur-[100px]" />
      </div>

      <button 
        onClick={toggleTheme}
        className="absolute top-6 right-6 p-2 rounded-full bg-white dark:bg-slate-800 shadow-lg text-slate-600 dark:text-slate-300 hover:text-slate-900 dark:hover:text-white transition-all z-50 border border-slate-200 dark:border-slate-700"
      >
        {theme === 'dark' ? <Sun className="w-5 h-5" /> : <Moon className="w-5 h-5" />}
      </button>

      <div className="z-10 w-full max-w-md space-y-8 text-center py-10">
        <div className="flex flex-col items-center gap-4">
          <div className="w-20 h-20 bg-white dark:bg-slate-900 rounded-2xl flex items-center justify-center shadow-2xl shadow-emergency-900/10 dark:shadow-emergency-900/20 border border-slate-200 dark:border-slate-800">
             <AlertOctagon className="w-10 h-10 text-emergency-500" />
          </div>
          <h1 className="text-4xl font-black tracking-tighter text-transparent bg-clip-text bg-gradient-to-r from-slate-900 to-slate-600 dark:from-white dark:to-slate-400">
            ALERTA ESPAÑA
          </h1>
          <p className="text-slate-600 dark:text-slate-400 text-lg">
            Monitor de emergencias en tiempo real.
          </p>
          <div className="bg-yellow-100 dark:bg-yellow-900/20 border border-yellow-200 dark:border-yellow-700/50 px-3 py-1 rounded-full">
            <p className="text-xs text-yellow-700 dark:text-yellow-500 font-semibold tracking-wide uppercase">
              Solo disponible en territorio español 🇪🇸
            </p>
          </div>
        </div>

        <div className="w-full bg-white/80 dark:bg-slate-900/50 backdrop-blur-md p-6 rounded-2xl border border-slate-200 dark:border-slate-800 shadow-xl text-left transition-colors duration-300">

          <div className="mb-6">
             <label className="flex justify-between text-xs text-slate-500 dark:text-slate-400 mb-2 font-mono uppercase tracking-wider">
                <span>Radio de cobertura</span>
                <span className="text-slate-900 dark:text-white font-bold">{radius} km</span>
             </label>
             <input 
                type="range" 
                min="5" 
                max="100" 
                step="5"
                value={radius} 
                onChange={(e) => setRadius(Number(e.target.value))}
                className="w-full h-2 bg-slate-200 dark:bg-slate-700 rounded-lg appearance-none cursor-pointer accent-blue-500 hover:accent-blue-400 transition-colors"
             />
          </div>

          <button 
            onClick={handleGPSLocation}
            disabled={loading}
            className="w-full py-4 bg-blue-600 hover:bg-blue-500 text-white rounded-xl font-bold flex items-center justify-center gap-2 transition-all active:scale-95 mb-4 group shadow-lg shadow-blue-500/20"
          >
            {loading ? <Loader2 className="animate-spin" /> : <Navigation className="w-5 h-5 group-hover:animate-pulse" />}
            Usar mi ubicación actual
          </button>

          <div className="relative flex py-2 items-center">
            <div className="flex-grow border-t border-slate-200 dark:border-slate-800"></div>
            <span className="flex-shrink mx-4 text-slate-400 dark:text-slate-500 text-xs uppercase tracking-widest">o busca tu ciudad</span>
            <div className="flex-grow border-t border-slate-200 dark:border-slate-800"></div>
          </div>

          <form onSubmit={handleManualLocation} className="mt-4 flex gap-2">
            <input 
              type="text" 
              placeholder="Ej: Toledo, Valencia, Madrid..." 
              className="flex-1 bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-700 rounded-xl px-4 py-3 text-slate-900 dark:text-white focus:outline-none focus:border-blue-500 transition-colors placeholder:text-slate-400"
              value={location.name}
              onChange={(e) => setLocation({ ...location, name: e.target.value })}
            />
            <button 
              type="submit"
              disabled={loading || !location.name}
              className="bg-slate-100 dark:bg-slate-800 hover:bg-slate-200 dark:hover:bg-slate-700 text-slate-700 dark:text-white p-3 rounded-xl transition-colors border border-slate-200 dark:border-slate-700 disabled:opacity-50"
            >
              {loading ? <Loader2 className="animate-spin w-5 h-5" /> : <Search className="w-5 h-5" />}
            </button>
          </form>

          <button 
            onClick={() => setView(ViewState.HISTORY)}
            className="w-full mt-4 py-2 text-xs text-slate-500 hover:text-slate-700 dark:hover:text-slate-300 flex items-center justify-center gap-1 transition-colors"
          >
            <History className="w-3 h-3" />
            Búsqueda histórica
          </button>
        </div>

        {/* Disclaimer Onboarding */}
        <div className="w-full bg-slate-100 dark:bg-slate-900/30 p-4 rounded-xl border border-slate-200 dark:border-slate-800/50 flex gap-3 text-left">
            <Info className="w-5 h-5 text-slate-400 flex-shrink-0 mt-0.5" />
            <p className="text-[11px] text-slate-500 dark:text-slate-400 leading-relaxed">
                <span className="font-bold uppercase block mb-1">Origen de los datos</span>
                Esta aplicación utiliza IA para agregar información de fuentes oficiales (AEMET, DGT, 112), noticias locales y señales sociales. 
                <span className="block mt-1">No es un canal oficial de emergencias. En caso de peligro real, siga las instrucciones de las autoridades y llame al 112.</span>
            </p>
        </div>
      </div>
    </div>
  );

  const renderHistory = () => (
    <div className="flex flex-col items-center justify-center min-h-screen p-6 bg-slate-50 dark:bg-slate-950 transition-colors duration-300">
      <div className="w-full max-w-md bg-white/80 dark:bg-slate-900/80 p-6 rounded-2xl border border-slate-200 dark:border-slate-800 shadow-xl backdrop-blur-md">
        <div className="flex items-center gap-2 mb-6 cursor-pointer group" onClick={() => setView(ViewState.ONBOARDING)}>
          <Calendar className="w-6 h-6 text-purple-500" />
          <span className="text-xl font-bold text-slate-900 dark:text-slate-300 group-hover:text-purple-500 transition-colors">Archivo Histórico</span>
        </div>

        <form onSubmit={handleHistorySearch} className="space-y-4">
          <div>
            <label className="text-xs text-slate-500 dark:text-slate-400 uppercase font-bold mb-1 block">Ubicación</label>
            <div className="flex gap-2">
                <input 
                  type="text"
                  required
                  value={historyLocation}
                  onChange={(e) => setHistoryLocation(e.target.value)}
                  placeholder="Ciudad o región"
                  className="flex-1 bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-700 rounded-lg px-4 py-3 text-slate-900 dark:text-white focus:border-purple-500 focus:outline-none transition-colors"
                />
                <button 
                    type="button"
                    onClick={handleHistoryGPS}
                    className="bg-slate-100 dark:bg-slate-800 hover:bg-slate-200 dark:hover:bg-slate-700 text-slate-700 dark:text-white px-3 rounded-lg border border-slate-200 dark:border-slate-700 transition-colors flex items-center justify-center"
                    disabled={loading}
                >
                    {loading && !historyLocation ? <Loader2 className="animate-spin w-5 h-5" /> : <Navigation className="w-5 h-5 text-blue-500 dark:text-blue-400" />}
                </button>
            </div>
          </div>

          <div>
             <label className="text-xs text-slate-500 dark:text-slate-400 uppercase font-bold mb-1 block">Categoría</label>
             <div className="relative">
                 <select 
                    value={formCategory}
                    onChange={(e) => setFormCategory(e.target.value)}
                    className="w-full bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-700 rounded-lg px-4 py-3 text-slate-900 dark:text-white appearance-none focus:border-purple-500 focus:outline-none"
                 >
                    {categories.map(c => <option key={c} value={c}>{c}</option>)}
                 </select>
                 <Filter className="absolute right-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500 pointer-events-none" />
             </div>
          </div>

          <div>
            <label className="text-xs text-slate-500 dark:text-slate-400 uppercase font-bold mb-1 block">Fecha del Evento</label>
            <div className="grid grid-cols-3 gap-2">
                <div className="relative">
                   <select 
                      value={formDay} 
                      onChange={(e) => setFormDay(Number(e.target.value))}
                      className="w-full bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-700 rounded-lg px-2 py-3 text-slate-900 dark:text-white appearance-none text-center focus:border-purple-500 focus:outline-none"
                   >
                     {days.map(d => <option key={d} value={d}>{d}</option>)}
                   </select>
                   <span className="absolute right-2 top-1/2 -translate-y-1/2 pointer-events-none text-slate-500 text-xs">Día</span>
                </div>

                <div className="relative">
                    <select 
                        value={formMonth} 
                        onChange={(e) => {
                            const newMonth = Number(e.target.value);
                            setFormMonth(newMonth);
                            const maxDay = new Date(formYear, newMonth + 1, 0).getDate();
                            if (formDay > maxDay) setFormDay(maxDay);
                        }}
                        className="w-full bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-700 rounded-lg px-2 py-3 text-slate-900 dark:text-white appearance-none text-center focus:border-purple-500 focus:outline-none"
                    >
                        {months.map((m, idx) => <option key={idx} value={idx}>{m.substring(0,3)}</option>)}
                    </select>
                     <span className="absolute right-2 top-1/2 -translate-y-1/2 pointer-events-none text-slate-500 text-xs">Mes</span>
                </div>

                 <div className="relative">
                    <select 
                        value={formYear} 
                        onChange={(e) => setFormYear(Number(e.target.value))}
                        className="w-full bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-700 rounded-lg px-2 py-3 text-slate-900 dark:text-white appearance-none text-center focus:border-purple-500 focus:outline-none"
                    >
                        {years.map(y => <option key={y} value={y}>{y}</option>)}
                    </select>
                     <span className="absolute right-2 top-1/2 -translate-y-1/2 pointer-events-none text-slate-500 text-xs">Año</span>
                 </div>
            </div>
          </div>
          <button 
            type="submit"
            disabled={loading}
            className="w-full bg-purple-600 hover:bg-purple-500 text-white py-3 rounded-lg font-bold flex items-center justify-center gap-2 transition-all active:scale-95 shadow-lg shadow-purple-500/20"
          >
             {loading ? <Loader2 className="animate-spin" /> : <Search className="w-4 h-4" />}
             Buscar en el pasado
          </button>
        </form>
        <button onClick={() => setView(ViewState.ONBOARDING)} className="mt-4 text-sm text-slate-500 hover:text-slate-800 dark:hover:text-slate-200 w-full text-center transition-colors">Cancelar</button>
      </div>
    </div>
  );

  const renderDashboard = () => (
    <div className="min-h-screen bg-slate-50 dark:bg-slate-950 flex flex-col transition-colors duration-300">
      <header className="sticky top-0 z-50 bg-white/90 dark:bg-slate-900/90 backdrop-blur-md border-b border-slate-200 dark:border-slate-800 px-4 py-3 shadow-lg transition-colors">
        <div className="flex justify-between items-center max-w-2xl mx-auto">
          <div className="flex items-center gap-2 cursor-pointer" onClick={() => setView(ViewState.ONBOARDING)}>
            <MapPin className="text-emergency-500 w-5 h-5" />
            <h2 className="font-bold text-lg text-slate-900 dark:text-white truncate max-w-[150px] sm:max-w-none capitalize">{location.name}</h2>
          </div>
          <div className="flex gap-2">
            {!historyDate && (
               <button
                  onClick={toggleMonitoring}
                  className={`p-2 rounded-full transition-all ${isMonitoring ? 'bg-emergency-500/20 text-emergency-500 ring-2 ring-emergency-500/50' : 'bg-slate-100 dark:bg-slate-800 text-slate-400 dark:text-slate-400 hover:text-slate-700 dark:hover:text-white'}`}
                  title={isMonitoring ? "Monitorización activada" : "Activar monitorización"}
               >
                  {isMonitoring ? <Bell className="w-5 h-5 animate-pulse" /> : <BellOff className="w-5 h-5" />}
               </button>
            )}
             <button
                onClick={toggleTheme}
                className="p-2 rounded-full bg-slate-100 dark:bg-slate-800 text-slate-400 hover:text-slate-700 dark:hover:text-white transition-all border border-slate-200 dark:border-transparent"
             >
                {theme === 'dark' ? <Sun className="w-5 h-5" /> : <Moon className="w-5 h-5" />}
             </button>
            <button 
               onClick={() => executeSearch(location.name, historyDate || undefined, radius, activeHistoryCategory)}
               className="p-2 bg-slate-100 dark:bg-slate-800 rounded-full text-slate-400 hover:text-slate-700 dark:hover:text-white transition-all border border-slate-200 dark:border-transparent"
            >
              <RotateCw className={`w-5 h-5 ${loading ? 'animate-spin' : ''}`} />
            </button>
             <button 
               onClick={() => {
                   setHistoryDate(''); 
                   setHistoryLocation('');
                   setView(ViewState.ONBOARDING);
                   setIsMonitoring(false);
               }}
               className="p-2 bg-slate-100 dark:bg-slate-800 rounded-full text-slate-400 hover:text-slate-700 dark:hover:text-white transition-all border border-slate-200 dark:border-transparent"
            >
              <Search className="w-5 h-5" />
            </button>
          </div>
        </div>
      </header>

      <main className="flex-1 p-4 max-w-2xl mx-auto w-full overflow-y-auto no-scrollbar pb-32">
        {loading ? (
            <div className="flex flex-col items-center justify-center h-64 space-y-4 opacity-50">
                <Loader2 className="w-10 h-10 animate-spin text-blue-500" />
                <p className="animate-pulse text-slate-600 dark:text-slate-400 text-center">Analizando redes sociales y fuentes oficiales españolas...</p>
            </div>
        ) : (
            <>
                {isMonitoring && !historyDate && (
                   <div className="bg-emergency-50 dark:bg-emergency-900/30 border border-emergency-200 dark:border-emergency-500/30 rounded-lg p-3 mb-4 flex items-center justify-between animate-pulse">
                      <div className="flex items-center gap-2 text-emergency-700 dark:text-emergency-200">
                         <span className="relative flex h-3 w-3">
                           <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-red-400 opacity-75"></span>
                           <span className="relative inline-flex rounded-full h-3 w-3 bg-red-500"></span>
                         </span>
                         <span className="text-xs font-bold uppercase tracking-wider">Monitorizando ({radius}km)</span>
                      </div>
                      <span className="text-xs text-emergency-600/70 dark:text-emergency-200/50 font-mono">Actualiza cada 60s</span>
                   </div>
                )}

                {historyDate && (
                     <div className="bg-purple-50 dark:bg-purple-900/30 border border-purple-200 dark:border-purple-500/30 rounded-lg p-3 mb-4 flex flex-col gap-1">
                        <div className="flex items-center gap-3">
                             <Calendar className="w-5 h-5 text-purple-600 dark:text-purple-400" />
                            <div>
                                <div className="text-purple-800 dark:text-purple-200 text-sm font-bold">Archivo Histórico</div>
                                <div className="text-purple-600/70 dark:text-purple-300/70 text-xs">Eventos del {historyDate}</div>
                            </div>
                        </div>
                     </div>
                )}

                <StatsChart events={alerts} />

                <div className="bg-white dark:bg-gradient-to-r dark:from-slate-900 dark:to-slate-800 p-4 rounded-xl border border-slate-200 dark:border-slate-700 mb-6 relative overflow-hidden shadow-sm transition-colors">
                    <h3 className="text-xs font-bold text-blue-600 dark:text-blue-400 uppercase tracking-wider mb-2 flex items-center gap-1">
                        <AlertOctagon className="w-3 h-3" />
                        Informe de Situación
                    </h3>
                    <p className="text-sm leading-relaxed text-slate-700 dark:text-slate-200">{analysis}</p>
                </div>

                <h3 className="text-lg font-bold text-slate-900 dark:text-white mb-3">Eventos Detectados ({alerts.length})</h3>
                <div className="space-y-4">
                    {alerts.map(event => (
                        <AlertCard key={event.id} event={event} />
                    ))}
                    {alerts.length === 0 && (
                        <div className="text-center py-10 text-slate-500 border border-dashed border-slate-300 dark:border-slate-800 rounded-xl">
                            No se encontraron eventos significativos.
                        </div>
                    )}
                </div>

                {/* Dashboard Tiny Disclaimer */}
                <div className="mt-10 p-4 border-t border-slate-200 dark:border-slate-800 flex flex-col items-center text-center gap-2">
                    <div className="flex items-center gap-2 text-slate-400 dark:text-slate-500">
                        <ShieldAlert className="w-4 h-4" />
                        <span className="text-[10px] uppercase font-bold tracking-widest">Información IA</span>
                    </div>
                    <p className="text-[10px] text-slate-400 dark:text-slate-500 leading-tight">
                        Este reporte agrega datos de fuentes oficiales, prensa y redes sociales mediante procesamiento de IA. 
                        No sustituye avisos de emergencia oficiales. Siga siempre a @emergencias112 y autoridades locales.
                    </p>
                </div>
            </>
        )}
      </main>

      <div className="fixed bottom-0 w-full bg-white dark:bg-slate-900 border-t border-slate-200 dark:border-slate-800 p-3 text-xs text-slate-500 dark:text-slate-400 flex justify-center gap-4 z-40 max-w-2xl left-1/2 -translate-x-1/2 rounded-t-xl transition-colors shadow-[0_-5px_15px_rgba(0,0,0,0.05)]">
          <div className="flex items-center gap-1"><span className="w-2 h-2 rounded-full bg-red-500"></span> Crítico</div>
          <div className="flex items-center gap-1"><span className="w-2 h-2 rounded-full bg-orange-500"></span> Aviso</div>
          <div className="flex items-center gap-1"><span className="w-2 h-2 rounded-full bg-blue-500"></span> Oficial</div>
          <div className="flex items-center gap-1"><span className="w-2 h-2 rounded-full bg-purple-500"></span> Social</div>
      </div>
    </div>
  );

  return (
    <>
      {view === ViewState.ONBOARDING && renderOnboarding()}
      {view === ViewState.HISTORY && renderHistory()}
      {view === ViewState.DASHBOARD && renderDashboard()}
    </>
  );
}

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { MapPin, Navigation, Search, History, AlertOctagon, RotateCw, Loader2, Bell, BellOff, Calendar, Filter, Sun, Moon, Info, ShieldAlert } from 'lucide-react';
import { AlertEvent, UserLocation, SeverityLevel } from './types';
import { fetchAlerts } from './services/geminiService';
import AlertCard from './components/AlertCard';
import StatsChart from './components/StatsChart';

enum ViewState {
  ONBOARDING,
  DASHBOARD,
  HISTORY
}

export default function App() {
  const [view, setView] = useState<ViewState>(ViewState.ONBOARDING);
  const [location, setLocation] = useState<UserLocation>({ name: '', isGPS: false });
  const [alerts, setAlerts] = useState<AlertEvent[]>([]);
  const [analysis, setAnalysis] = useState<string>('');
  const [loading, setLoading] = useState(false);
  const [radius, setRadius] = useState<number>(10); // Default 10km

  // Theme State
  const [theme, setTheme] = useState<'light' | 'dark'>(() => {
    if (typeof window !== 'undefined') {
        const saved = localStorage.getItem('theme');
        return (saved === 'light' || saved === 'dark') ? saved : 'dark';
    }
    return 'dark';
  });

  // Apply Theme
  useEffect(() => {
    const root = window.document.documentElement;
    if (theme === 'dark') {
        root.classList.add('dark');
    } else {
        root.classList.remove('dark');
    }
    localStorage.setItem('theme', theme);
  }, [theme]);

  const toggleTheme = () => setTheme(prev => prev === 'dark' ? 'light' : 'dark');

  // History Mode State - Active query
  const [historyDate, setHistoryDate] = useState<string>('');
  const [activeHistoryCategory, setActiveHistoryCategory] = useState<string>('');

  // History Form State
  const [historyLocation, setHistoryLocation] = useState<string>('');
  const [formDay, setFormDay] = useState<number>(new Date().getDate());
  const [formMonth, setFormMonth] = useState<number>(new Date().getMonth()); // 0-11
  const [formYear, setFormYear] = useState<number>(new Date().getFullYear());
  const [formCategory, setFormCategory] = useState<string>('TODAS');

  // Notification & Real-time State
  const [isMonitoring, setIsMonitoring] = useState(false);
  const [permission, setPermission] = useState<NotificationPermission>('default');
  const seenAlertsRef = useRef<Set<string>>(new Set());

  useEffect(() => {
    if ('Notification' in window) {
      setPermission(Notification.permission);
    }
  }, []);

  const requestNotificationPermission = async () => {
    if (!('Notification' in window)) {
      alert('Este navegador no soporta notificaciones.');
      return;
    }
    const result = await Notification.requestPermission();
    setPermission(result);
    if (result === 'granted') {
      setIsMonitoring(true);
      new Notification('Alertas Activas', {
        body: `Monitorización en tiempo real activada para ${location.name}.`,
        icon: '/favicon.ico'
      });
    }
  };

  const toggleMonitoring = () => {
    if (isMonitoring) {
      setIsMonitoring(false);
    } else {
      if (permission === 'granted') {
        setIsMonitoring(true);
      } else {
        requestNotificationPermission();
      }
    }
  };

  const checkAndNotify = (newAlerts: AlertEvent[]) => {
    if (permission !== 'granted' || !isMonitoring) return;

    newAlerts.forEach(alert => {
      if ((alert.severity === SeverityLevel.CRITICAL || alert.severity === SeverityLevel.WARNING) && 
          !seenAlertsRef.current.has(alert.id)) {

        seenAlertsRef.current.add(alert.id);

        new Notification(`⚠️ ${alert.severity}: ${alert.title}`, {
          body: alert.description,
          tag: alert.id,
          requireInteraction: alert.severity === SeverityLevel.CRITICAL
        });
      }
    });
  };

  useEffect(() => {
    if (view !== ViewState.DASHBOARD || historyDate || !isMonitoring || !location.name) return;

    const intervalId = setInterval(async () => {
      try {
        const result = await fetchAlerts(location.name, undefined, radius);
        setAlerts(result.events);
        setAnalysis(result.analysis);
        checkAndNotify(result.events);
      } catch (e) {
        console.error("Background polling failed", e);
      }
    }, 60000);

    return () => clearInterval(intervalId);
  }, [view, historyDate, isMonitoring, location.name, permission, radius]);


  const handleGPSLocation = () => {
    setLoading(true);
    if ('geolocation' in navigator) {
      navigator.geolocation.getCurrentPosition(
        async (position) => {
          const lat = position.coords.latitude.toFixed(4);
          const lng = position.coords.longitude.toFixed(4);

          setLocation({ lat: position.coords.latitude, lng: position.coords.longitude, name: `GPS: ${lat}, ${lng}`, isGPS: true });
          await executeSearch(`Coordenadas ${lat}, ${lng} España`, undefined, radius);
        },
        (error) => {
          console.error("GPS Error", error);
          setLoading(false);
          alert("No se pudo obtener el GPS. Por favor introduzca la ubicación manualmente.");
        }
      );
    } else {
      setLoading(false);
      alert("Geolocalización no soportada.");
    }
  };

  const handleHistoryGPS = () => {
    setLoading(true);
    if ('geolocation' in navigator) {
      navigator.geolocation.getCurrentPosition(
        (position) => {
          const lat = position.coords.latitude.toFixed(4);
          const lng = position.coords.longitude.toFixed(4);
          setHistoryLocation(`Coordenadas GPS: ${lat}, ${lng}`);
          setLoading(false);
        },
        (error) => {
          console.error("GPS Error", error);
          setLoading(false);
          alert("No se pudo obtener el GPS.");
        }
      );
    } else {
      setLoading(false);
      alert("Geolocalización no soportada.");
    }
  };

  const handleManualLocation = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!location.name) return;
    await executeSearch(location.name);
  };

  const executeSearch = async (locName: string, date?: string, searchRadius?: number, category?: string) => {
    setLoading(true);
    seenAlertsRef.current.clear();

    const effectiveRadius = searchRadius || radius;

    const result = await fetchAlerts(locName, date, effectiveRadius, category);
    setAlerts(result.events);
    setAnalysis(result.analysis);

    if (isMonitoring) {
        checkAndNotify(result.events);
    }

    if (!location.name || location.name.startsWith('GPS')) {
       setLocation(prev => ({ ...prev, name: locName }));
    }

    setLoading(false);
    setView(ViewState.DASHBOARD);
  };

  const handleHistorySearch = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!historyLocation) return;

    const mm = (formMonth + 1).toString().padStart(2, '0');
    const dd = formDay.toString().padStart(2, '0');
    const dateStr = `${formYear}-${mm}-${dd}`;

    setHistoryDate(dateStr);
    setActiveHistoryCategory(formCategory);

    setLoading(true);
    const result = await fetchAlerts(historyLocation, dateStr, undefined, formCategory);
    setAlerts(result.events);
    setAnalysis(result.analysis);
    setLocation({ name: historyLocation, isGPS: false });
    setIsMonitoring(false);
    setView(ViewState.DASHBOARD); 
    setLoading(false);
  };

  const months = [
    "Enero", "Febrero", "Marzo", "Abril", "Mayo", "Junio", 
    "Julio", "Agosto", "Septiembre", "Octubre", "Noviembre", "Diciembre"
  ];
  const currentYear = new Date().getFullYear();
  const years = Array.from({length: 30}, (_, i) => currentYear - i);
  const daysInMonth = new Date(formYear, formMonth + 1, 0).getDate();
  const days = Array.from({length: daysInMonth}, (_, i) => i + 1);

  const categories = [
    "TODAS", "Emergencias 112", "ES-Alert", "Incendios", "Clima / AEMET", "Tráfico / DGT", "Seguridad Ciudadana"
  ];

  const renderOnboarding = () => (
    <div className="flex flex-col items-center justify-start h-screen p-6 bg-slate-50 dark:bg-slate-950 relative overflow-y-auto transition-colors duration-300">
      <div className="absolute top-0 left-0 w-full h-full overflow-hidden pointer-events-none opacity-50 dark:opacity-100">
         <div className="absolute top-[-10%] left-[-10%] w-[50%] h-[50%] bg-emergency-500/10 rounded-full blur-[100px]" />
         <div className="absolute bottom-[-10%] right-[-10%] w-[50%] h-[50%] bg-blue-500/10 rounded-full blur-[100px]" />
      </div>

      <button 
        onClick={toggleTheme}
        className="absolute top-6 right-6 p-2 rounded-full bg-white dark:bg-slate-800 shadow-lg text-slate-600 dark:text-slate-300 hover:text-slate-900 dark:hover:text-white transition-all z-50 border border-slate-200 dark:border-slate-700"
      >
        {theme === 'dark' ? <Sun className="w-5 h-5" /> : <Moon className="w-5 h-5" />}
      </button>

      <div className="z-10 w-full max-w-md space-y-8 text-center py-12">
        <div className="flex flex-col items-center gap-4">
          <div className="w-20 h-20 bg-white dark:bg-slate-900 rounded-2xl flex items-center justify-center shadow-2xl shadow-emergency-900/10 dark:shadow-emergency-900/20 border border-slate-200 dark:border-slate-800">
             <AlertOctagon className="w-10 h-10 text-emergency-500" />
          </div>
          <h1 className="text-4xl font-black tracking-tighter text-transparent bg-clip-text bg-gradient-to-r from-slate-900 to-slate-600 dark:from-white dark:to-slate-400">
            ALERTA ESPAÑA
          </h1>
          <p className="text-slate-600 dark:text-slate-400 text-lg">
            Monitor de emergencias en tiempo real.
          </p>
          <div className="bg-yellow-100 dark:bg-yellow-900/20 border border-yellow-200 dark:border-yellow-700/50 px-3 py-1 rounded-full">
            <p className="text-xs text-yellow-700 dark:text-yellow-500 font-semibold tracking-wide uppercase">
              Solo disponible en territorio español 🇪🇸
            </p>
          </div>
        </div>

        <div className="w-full bg-white/80 dark:bg-slate-900/50 backdrop-blur-md p-6 rounded-2xl border border-slate-200 dark:border-slate-800 shadow-xl text-left transition-colors duration-300">
          <div className="mb-6">
             <label className="flex justify-between text-xs text-slate-500 dark:text-slate-400 mb-2 font-mono uppercase tracking-wider">
                <span>Radio de cobertura</span>
                <span className="text-slate-900 dark:text-white font-bold">{radius} km</span>
             </label>
             <input 
                type="range" 
                min="5" 
                max="100" 
                step="5"
                value={radius} 
                onChange={(e) => setRadius(Number(e.target.value))}
                className="w-full h-2 bg-slate-200 dark:bg-slate-700 rounded-lg appearance-none cursor-pointer accent-blue-500 hover:accent-blue-400 transition-colors"
             />
          </div>

          <button 
            onClick={handleGPSLocation}
            disabled={loading}
            className="w-full py-4 bg-blue-600 hover:bg-blue-500 text-white rounded-xl font-bold flex items-center justify-center gap-2 transition-all active:scale-95 mb-4 group shadow-lg shadow-blue-500/20"
          >
            {loading ? <Loader2 className="animate-spin" /> : <Navigation className="w-5 h-5 group-hover:animate-pulse" />}
            Usar mi ubicación actual
          </button>

          <div className="relative flex py-2 items-center">
            <div className="flex-grow border-t border-slate-200 dark:border-slate-800"></div>
            <span className="flex-shrink mx-4 text-slate-400 dark:text-slate-500 text-xs uppercase tracking-widest">o busca tu ciudad</span>
            <div className="flex-grow border-t border-slate-200 dark:border-slate-800"></div>
          </div>

          <form onSubmit={handleManualLocation} className="mt-4 flex gap-2">
            <input 
              type="text" 
              placeholder="Ej: Toledo, Valencia, Madrid..." 
              className="flex-1 bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-700 rounded-xl px-4 py-3 text-slate-900 dark:text-white focus:outline-none focus:border-blue-500 transition-colors placeholder:text-slate-400"
              value={location.name}
              onChange={(e) => setLocation({ ...location, name: e.target.value })}
            />
            <button 
              type="submit"
              disabled={loading || !location.name}
              className="bg-slate-100 dark:bg-slate-800 hover:bg-slate-200 dark:hover:bg-slate-700 text-slate-700 dark:text-white p-3 rounded-xl transition-colors border border-slate-200 dark:border-slate-700 disabled:opacity-50"
            >
              {loading ? <Loader2 className="animate-spin w-5 h-5" /> : <Search className="w-5 h-5" />}
            </button>
          </form>

          <button 
            onClick={() => setView(ViewState.HISTORY)}
            className="w-full mt-4 py-2 text-xs text-slate-500 hover:text-slate-700 dark:hover:text-slate-300 flex items-center justify-center gap-1 transition-colors"
          >
            <History className="w-3 h-3" />
            Búsqueda histórica
          </button>
        </div>

        <div className="w-full bg-slate-100 dark:bg-slate-900/30 p-4 rounded-xl border border-slate-200 dark:border-slate-800/50 flex gap-3 text-left">
            <Info className="w-5 h-5 text-slate-400 flex-shrink-0 mt-0.5" />
            <p className="text-[11px] text-slate-500 dark:text-slate-400 leading-relaxed">
                <span className="font-bold uppercase block mb-1">Origen de los datos</span>
                Esta aplicación utiliza IA para agregar información de fuentes oficiales (AEMET, DGT, 112), noticias locales y señales sociales. 
                <span className="block mt-1">No es un canal oficial de emergencias. En caso de peligro real, siga las instrucciones de las autoridades y llame al 112.</span>
            </p>
        </div>
      </div>
    </div>
  );

  const renderHistory = () => (
    <div className="flex flex-col items-center justify-start h-screen p-6 bg-slate-50 dark:bg-slate-950 overflow-y-auto transition-colors duration-300">
      <div className="w-full max-w-md bg-white/80 dark:bg-slate-900/80 p-6 rounded-2xl border border-slate-200 dark:border-slate-800 shadow-xl backdrop-blur-md my-12">
        <div className="flex items-center gap-2 mb-6 cursor-pointer group" onClick={() => setView(ViewState.ONBOARDING)}>
          <Calendar className="w-6 h-6 text-purple-500" />
          <span className="text-xl font-bold text-slate-900 dark:text-slate-300 group-hover:text-purple-500 transition-colors">Archivo Histórico</span>
        </div>

        <form onSubmit={handleHistorySearch} className="space-y-4">
          <div>
            <label className="text-xs text-slate-500 dark:text-slate-400 uppercase font-bold mb-1 block">Ubicación</label>
            <div className="flex gap-2">
                <input 
                  type="text"
                  required
                  value={historyLocation}
                  onChange={(e) => setHistoryLocation(e.target.value)}
                  placeholder="Ciudad o región"
                  className="flex-1 bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-700 rounded-lg px-4 py-3 text-slate-900 dark:text-white focus:border-purple-500 focus:outline-none transition-colors"
                />
                <button 
                    type="button"
                    onClick={handleHistoryGPS}
                    className="bg-slate-100 dark:bg-slate-800 hover:bg-slate-200 dark:hover:bg-slate-700 text-slate-700 dark:text-white px-3 rounded-lg border border-slate-200 dark:border-slate-700 transition-colors flex items-center justify-center"
                    disabled={loading}
                >
                    {loading && !historyLocation ? <Loader2 className="animate-spin w-5 h-5" /> : <Navigation className="w-5 h-5 text-blue-500 dark:text-blue-400" />}
                </button>
            </div>
          </div>

          <div>
             <label className="text-xs text-slate-500 dark:text-slate-400 uppercase font-bold mb-1 block">Categoría</label>
             <div className="relative">
                 <select 
                    value={formCategory}
                    onChange={(e) => setFormCategory(e.target.value)}
                    className="w-full bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-700 rounded-lg px-4 py-3 text-slate-900 dark:text-white appearance-none focus:border-purple-500 focus:outline-none"
                 >
                    {categories.map(c => <option key={c} value={c}>{c}</option>)}
                 </select>
                 <Filter className="absolute right-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500 pointer-events-none" />
             </div>
          </div>

          <div>
            <label className="text-xs text-slate-500 dark:text-slate-400 uppercase font-bold mb-1 block">Fecha del Evento</label>
            <div className="grid grid-cols-3 gap-2">
                <div className="relative">
                   <select 
                      value={formDay} 
                      onChange={(e) => setFormDay(Number(e.target.value))}
                      className="w-full bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-700 rounded-lg px-2 py-3 text-slate-900 dark:text-white appearance-none text-center focus:border-purple-500 focus:outline-none"
                   >
                     {days.map(d => <option key={d} value={d}>{d}</option>)}
                   </select>
                   <span className="absolute right-2 top-1/2 -translate-y-1/2 pointer-events-none text-slate-500 text-xs">Día</span>
                </div>

                <div className="relative">
                    <select 
                        value={formMonth} 
                        onChange={(e) => {
                            const newMonth = Number(e.target.value);
                            setFormMonth(newMonth);
                            const maxDay = new Date(formYear, newMonth + 1, 0).getDate();
                            if (formDay > maxDay) setFormDay(maxDay);
                        }}
                        className="w-full bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-700 rounded-lg px-2 py-3 text-slate-900 dark:text-white appearance-none text-center focus:border-purple-500 focus:outline-none"
                    >
                        {months.map((m, idx) => <option key={idx} value={idx}>{m.substring(0,3)}</option>)}
                    </select>
                     <span className="absolute right-2 top-1/2 -translate-y-1/2 pointer-events-none text-slate-500 text-xs">Mes</span>
                </div>

                 <div className="relative">
                    <select 
                        value={formYear} 
                        onChange={(e) => setFormYear(Number(e.target.value))}
                        className="w-full bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-700 rounded-lg px-2 py-3 text-slate-900 dark:text-white appearance-none text-center focus:border-purple-500 focus:outline-none"
                    >
                        {years.map(y => <option key={y} value={y}>{y}</option>)}
                    </select>
                     <span className="absolute right-2 top-1/2 -translate-y-1/2 pointer-events-none text-slate-500 text-xs">Año</span>
                 </div>
            </div>
          </div>
          <button 
            type="submit"
            disabled={loading}
            className="w-full bg-purple-600 hover:bg-purple-500 text-white py-3 rounded-lg font-bold flex items-center justify-center gap-2 transition-all active:scale-95 shadow-lg shadow-purple-500/20"
          >
             {loading ? <Loader2 className="animate-spin" /> : <Search className="w-4 h-4" />}
             Buscar en el pasado
          </button>
        </form>
        <button onClick={() => setView(ViewState.ONBOARDING)} className="mt-4 text-sm text-slate-500 hover:text-slate-800 dark:hover:text-slate-200 w-full text-center transition-colors">Cancelar</button>
      </div>
    </div>
  );

  const renderDashboard = () => (
    <div className="h-screen bg-slate-50 dark:bg-slate-950 flex flex-col transition-colors duration-300">
      <header className="flex-shrink-0 sticky top-0 z-50 bg-white/90 dark:bg-slate-900/90 backdrop-blur-md border-b border-slate-200 dark:border-slate-800 px-4 py-3 shadow-lg transition-colors">
        <div className="flex justify-between items-center max-w-2xl mx-auto">
          <div className="flex items-center gap-2 cursor-pointer" onClick={() => setView(ViewState.ONBOARDING)}>
            <MapPin className="text-emergency-500 w-5 h-5" />
            <h2 className="font-bold text-lg text-slate-900 dark:text-white truncate max-w-[150px] sm:max-w-none capitalize">{location.name}</h2>
          </div>
          <div className="flex gap-2">
            {!historyDate && (
               <button
                  onClick={toggleMonitoring}
                  className={`p-2 rounded-full transition-all ${isMonitoring ? 'bg-emergency-500/20 text-emergency-500 ring-2 ring-emergency-500/50' : 'bg-slate-100 dark:bg-slate-800 text-slate-400 dark:text-slate-400 hover:text-slate-700 dark:hover:text-white'}`}
                  title={isMonitoring ? "Monitorización activada" : "Activar monitorización"}
               >
                  {isMonitoring ? <Bell className="w-5 h-5 animate-pulse" /> : <BellOff className="w-5 h-5" />}
               </button>
            )}
             <button
                onClick={toggleTheme}
                className="p-2 rounded-full bg-slate-100 dark:bg-slate-800 text-slate-400 hover:text-slate-700 dark:hover:text-white transition-all border border-slate-200 dark:border-transparent"
             >
                {theme === 'dark' ? <Sun className="w-5 h-5" /> : <Moon className="w-5 h-5" />}
             </button>
            <button 
               onClick={() => executeSearch(location.name, historyDate || undefined, radius, activeHistoryCategory)}
               className="p-2 bg-slate-100 dark:bg-slate-800 rounded-full text-slate-400 hover:text-slate-700 dark:hover:text-white transition-all border border-slate-200 dark:border-transparent"
            >
              <RotateCw className={`w-5 h-5 ${loading ? 'animate-spin' : ''}`} />
            </button>
             <button 
               onClick={() => {
                   setHistoryDate(''); 
                   setHistoryLocation('');
                   setView(ViewState.ONBOARDING);
                   setIsMonitoring(false);
               }}
               className="p-2 bg-slate-100 dark:bg-slate-800 rounded-full text-slate-400 hover:text-slate-700 dark:hover:text-white transition-all border border-slate-200 dark:border-transparent"
            >
              <Search className="w-5 h-5" />
            </button>
          </div>
        </div>
      </header>

      <main className="flex-1 p-4 max-w-2xl mx-auto w-full overflow-y-auto pb-40">
        {loading ? (
            <div className="flex flex-col items-center justify-center h-full space-y-4 opacity-50">
                <Loader2 className="w-10 h-10 animate-spin text-blue-500" />
                <p className="animate-pulse text-slate-600 dark:text-slate-400 text-center">Analizando redes sociales y fuentes oficiales españolas...</p>
            </div>
        ) : (
            <>
                {isMonitoring && !historyDate && (
                   <div className="bg-emergency-50 dark:bg-emergency-900/30 border border-emergency-200 dark:border-emergency-500/30 rounded-lg p-3 mb-4 flex items-center justify-between animate-pulse">
                      <div className="flex items-center gap-2 text-emergency-700 dark:text-emergency-200">
                         <span className="relative flex h-3 w-3">
                           <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-red-400 opacity-75"></span>
                           <span className="relative inline-flex rounded-full h-3 w-3 bg-red-500"></span>
                         </span>
                         <span className="text-xs font-bold uppercase tracking-wider">Monitorizando ({radius}km)</span>
                      </div>
                      <span className="text-xs text-emergency-600/70 dark:text-emergency-200/50 font-mono">Actualiza cada 60s</span>
                   </div>
                )}

                {historyDate && (
                     <div className="bg-purple-50 dark:bg-purple-900/30 border border-purple-200 dark:border-purple-500/30 rounded-lg p-3 mb-4 flex flex-col gap-1">
                        <div className="flex items-center gap-3">
                             <Calendar className="w-5 h-5 text-purple-600 dark:text-purple-400" />
                            <div>
                                <div className="text-purple-800 dark:text-purple-200 text-sm font-bold">Archivo Histórico</div>
                                <div className="text-purple-600/70 dark:text-purple-300/70 text-xs">Eventos del {historyDate}</div>
                            </div>
                        </div>
                     </div>
                )}

                <StatsChart events={alerts} />

                <div className="bg-white dark:bg-gradient-to-r dark:from-slate-900 dark:to-slate-800 p-4 rounded-xl border border-slate-200 dark:border-slate-700 mb-6 relative overflow-hidden shadow-sm transition-colors">
                    <h3 className="text-xs font-bold text-blue-600 dark:text-blue-400 uppercase tracking-wider mb-2 flex items-center gap-1">
                        <AlertOctagon className="w-3 h-3" />
                        Informe de Situación
                    </h3>
                    <p className="text-sm leading-relaxed text-slate-700 dark:text-slate-200">{analysis}</p>
                </div>

                <h3 className="text-lg font-bold text-slate-900 dark:text-white mb-3">Eventos Detectados ({alerts.length})</h3>
                <div className="space-y-4">
                    {alerts.map(event => (
                        <AlertCard key={event.id} event={event} />
                    ))}
                    {alerts.length === 0 && (
                        <div className="text-center py-10 text-slate-500 border border-dashed border-slate-300 dark:border-slate-800 rounded-xl">
                            No se encontraron eventos significativos.
                        </div>
                    )}
                </div>

                <div className="mt-10 p-4 border-t border-slate-200 dark:border-slate-800 flex flex-col items-center text-center gap-2">
                    <div className="flex items-center gap-2 text-slate-400 dark:text-slate-500">
                        <ShieldAlert className="w-4 h-4" />
                        <span className="text-[10px] uppercase font-bold tracking-widest">Información IA</span>
                    </div>
                    <p className="text-[10px] text-slate-400 dark:text-slate-500 leading-tight">
                        Este reporte agrega datos de fuentes oficiales, prensa y redes sociales mediante procesamiento de IA. 
                        No sustituye avisos de emergencia oficiales. Siga siempre a @emergencias112 y autoridades locales.
                    </p>
                </div>
            </>
        )}
      </main>

      <div className="fixed bottom-0 w-full bg-white dark:bg-slate-900 border-t border-slate-200 dark:border-slate-800 p-3 text-xs text-slate-500 dark:text-slate-400 flex justify-center gap-4 z-40 max-w-2xl left-1/2 -translate-x-1/2 rounded-t-xl transition-colors shadow-[0_-5px_15px_rgba(0,0,0,0.05)]">
          <div className="flex items-center gap-1"><span className="w-2 h-2 rounded-full bg-red-500"></span> Crítico</div>
          <div className="flex items-center gap-1"><span className="w-2 h-2 rounded-full bg-orange-500"></span> Aviso</div>
          <div className="flex items-center gap-1"><span className="w-2 h-2 rounded-full bg-blue-500"></span> Oficial</div>
          <div className="flex items-center gap-1"><span className="w-2 h-2 rounded-full bg-purple-500"></span> Social</div>
      </div>
    </div>
  );

  return (
    <>
      {view === ViewState.ONBOARDING && renderOnboarding()}
      {view === ViewState.HISTORY && renderHistory()}
      {view === ViewState.DASHBOARD && renderDashboard()}
    </>
  );
}

{
  "name": "Monitor de Emergencias",
  "description": "Real-time emergency and situational awareness monitor for Spain, aggregating official and social sources.",
  "requestFramePermissions": [
    "geolocation"
  ]
}

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { MapPin, Navigation, Search, History, AlertOctagon, RotateCw, Loader2, Bell, BellOff, Calendar, Filter, Sun, Moon, Info, ShieldAlert } from 'lucide-react';
import { AlertEvent, UserLocation, SeverityLevel } from './types';
import { fetchAlerts } from './services/geminiService';
import AlertCard from './components/AlertCard';
import StatsChart from './components/StatsChart';

enum ViewState {
  ONBOARDING,
  DASHBOARD,
  HISTORY
}

export default function App() {
  const [view, setView] = useState<ViewState>(ViewState.ONBOARDING);
  const [location, setLocation] = useState<UserLocation>({ name: '', isGPS: false });
  const [alerts, setAlerts] = useState<AlertEvent[]>([]);
  const [analysis, setAnalysis] = useState<string>('');
  const [loading, setLoading] = useState(false);
  const [radius, setRadius] = useState<number>(10); // Default 10km

  // Theme State
  const [theme, setTheme] = useState<'light' | 'dark'>(() => {
    if (typeof window !== 'undefined') {
        const saved = localStorage.getItem('theme');
        return (saved === 'light' || saved === 'dark') ? saved : 'dark';
    }
    return 'dark';
  });

  // Apply Theme
  useEffect(() => {
    const root = window.document.documentElement;
    if (theme === 'dark') {
        root.classList.add('dark');
    } else {
        root.classList.remove('dark');
    }
    localStorage.setItem('theme', theme);
  }, [theme]);

  const toggleTheme = () => setTheme(prev => prev === 'dark' ? 'light' : 'dark');

  // History Mode State - Active query
  const [historyDate, setHistoryDate] = useState<string>('');
  const [activeHistoryCategory, setActiveHistoryCategory] = useState<string>('');

  // History Form State
  const [historyLocation, setHistoryLocation] = useState<string>('');
  const [formDay, setFormDay] = useState<number>(new Date().getDate());
  const [formMonth, setFormMonth] = useState<number>(new Date().getMonth()); // 0-11
  const [formYear, setFormYear] = useState<number>(new Date().getFullYear());
  const [formCategory, setFormCategory] = useState<string>('TODAS');

  // Notification & Real-time State
  const [isMonitoring, setIsMonitoring] = useState(false);
  const [permission, setPermission] = useState<NotificationPermission>('default');
  const seenAlertsRef = useRef<Set<string>>(new Set());

  useEffect(() => {
    if ('Notification' in window) {
      setPermission(Notification.permission);
    }
  }, []);

  const requestNotificationPermission = async () => {
    if (!('Notification' in window)) {
      alert('Este navegador no soporta notificaciones.');
      return;
    }
    const result = await Notification.requestPermission();
    setPermission(result);
    if (result === 'granted') {
      setIsMonitoring(true);
      new Notification('Alertas Activas', {
        body: `Monitorización en tiempo real activada para ${location.name}.`,
        icon: '/favicon.ico'
      });
    }
  };

  const toggleMonitoring = () => {
    if (isMonitoring) {
      setIsMonitoring(false);
    } else {
      if (permission === 'granted') {
        setIsMonitoring(true);
      } else {
        requestNotificationPermission();
      }
    }
  };

  const checkAndNotify = (newAlerts: AlertEvent[]) => {
    if (permission !== 'granted' || !isMonitoring) return;

    newAlerts.forEach(alert => {
      if ((alert.severity === SeverityLevel.CRITICAL || alert.severity === SeverityLevel.WARNING) && 
          !seenAlertsRef.current.has(alert.id)) {

        seenAlertsRef.current.add(alert.id);

        new Notification(`⚠️ ${alert.severity}: ${alert.title}`, {
          body: alert.description,
          tag: alert.id,
          requireInteraction: alert.severity === SeverityLevel.CRITICAL
        });
      }
    });
  };

  useEffect(() => {
    if (view !== ViewState.DASHBOARD || historyDate || !isMonitoring || !location.name) return;

    const intervalId = setInterval(async () => {
      try {
        const result = await fetchAlerts(location.name, undefined, radius);
        setAlerts(result.events);
        setAnalysis(result.analysis);
        checkAndNotify(result.events);
      } catch (e) {
        console.error("Background polling failed", e);
      }
    }, 60000);

    return () => clearInterval(intervalId);
  }, [view, historyDate, isMonitoring, location.name, permission, radius]);


  const handleGPSLocation = () => {
    setLoading(true);
    if ('geolocation' in navigator) {
      navigator.geolocation.getCurrentPosition(
        async (position) => {
          const lat = position.coords.latitude.toFixed(4);
          const lng = position.coords.longitude.toFixed(4);

          setLocation({ lat: position.coords.latitude, lng: position.coords.longitude, name: `GPS: ${lat}, ${lng}`, isGPS: true });
          await executeSearch(`Coordenadas ${lat}, ${lng} España`, undefined, radius);
        },
        (error) => {
          console.error("GPS Error", error);
          setLoading(false);
          alert("No se pudo obtener el GPS. Por favor introduzca la ubicación manualmente.");
        }
      );
    } else {
      setLoading(false);
      alert("Geolocalización no soportada.");
    }
  };

  const handleHistoryGPS = () => {
    setLoading(true);
    if ('geolocation' in navigator) {
      navigator.geolocation.getCurrentPosition(
        (position) => {
          const lat = position.coords.latitude.toFixed(4);
          const lng = position.coords.longitude.toFixed(4);
          setHistoryLocation(`Coordenadas GPS: ${lat}, ${lng}`);
          setLoading(false);
        },
        (error) => {
          console.error("GPS Error", error);
          setLoading(false);
          alert("No se pudo obtener el GPS.");
        }
      );
    } else {
      setLoading(false);
      alert("Geolocalización no soportada.");
    }
  };

  const handleManualLocation = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!location.name) return;
    await executeSearch(location.name);
  };

  const executeSearch = async (locName: string, date?: string, searchRadius?: number, category?: string) => {
    setLoading(true);
    seenAlertsRef.current.clear();

    const effectiveRadius = searchRadius || radius;

    const result = await fetchAlerts(locName, date, effectiveRadius, category);
    setAlerts(result.events);
    setAnalysis(result.analysis);

    if (isMonitoring) {
        checkAndNotify(result.events);
    }

    if (!location.name || location.name.startsWith('GPS')) {
       setLocation(prev => ({ ...prev, name: locName }));
    }

    setLoading(false);
    setView(ViewState.DASHBOARD);
  };

  const handleHistorySearch = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!historyLocation) return;

    const mm = (formMonth + 1).toString().padStart(2, '0');
    const dd = formDay.toString().padStart(2, '0');
    const dateStr = `${formYear}-${mm}-${dd}`;

    setHistoryDate(dateStr);
    setActiveHistoryCategory(formCategory);

    setLoading(true);
    const result = await fetchAlerts(historyLocation, dateStr, undefined, formCategory);
    setAlerts(result.events);
    setAnalysis(result.analysis);
    setLocation({ name: historyLocation, isGPS: false });
    setIsMonitoring(false);
    setView(ViewState.DASHBOARD); 
    setLoading(false);
  };

  const months = [
    "Enero", "Febrero", "Marzo", "Abril", "Mayo", "Junio", 
    "Julio", "Agosto", "Septiembre", "Octubre", "Noviembre", "Diciembre"
  ];
  const currentYear = new Date().getFullYear();
  const years = Array.from({length: 30}, (_, i) => currentYear - i);
  const daysInMonth = new Date(formYear, formMonth + 1, 0).getDate();
  const days = Array.from({length: daysInMonth}, (_, i) => i + 1);

  const categories = [
    "TODAS", "Emergencias 112", "ES-Alert", "Incendios", "Clima / AEMET", "Tráfico / DGT", "Seguridad Ciudadana"
  ];

  const renderOnboarding = () => (
    <div className="flex flex-col items-center justify-start h-screen p-6 bg-slate-50 dark:bg-slate-950 relative overflow-y-auto transition-colors duration-300">
      <div className="absolute top-0 left-0 w-full h-full overflow-hidden pointer-events-none opacity-50 dark:opacity-100">
         <div className="absolute top-[-10%] left-[-10%] w-[50%] h-[50%] bg-emergency-500/10 rounded-full blur-[100px]" />
         <div className="absolute bottom-[-10%] right-[-10%] w-[50%] h-[50%] bg-blue-500/10 rounded-full blur-[100px]" />
      </div>

      <button 
        onClick={toggleTheme}
        className="absolute top-6 right-6 p-2 rounded-full bg-white dark:bg-slate-800 shadow-lg text-slate-600 dark:text-slate-300 hover:text-slate-900 dark:hover:text-white transition-all z-50 border border-slate-200 dark:border-slate-700"
      >
        {theme === 'dark' ? <Sun className="w-5 h-5" /> : <Moon className="w-5 h-5" />}
      </button>

      <div className="z-10 w-full max-w-md space-y-8 text-center py-12">
        <div className="flex flex-col items-center gap-4">
          <div className="w-20 h-20 bg-white dark:bg-slate-900 rounded-2xl flex items-center justify-center shadow-2xl shadow-emergency-900/10 dark:shadow-emergency-900/20 border border-slate-200 dark:border-slate-800">
             <AlertOctagon className="w-10 h-10 text-emergency-500" />
          </div>
          <h1 className="text-4xl font-black tracking-tighter text-transparent bg-clip-text bg-gradient-to-r from-slate-900 to-slate-600 dark:from-white dark:to-slate-400 uppercase">
            Monitor de Emergencias
          </h1>
          <p className="text-slate-600 dark:text-slate-400 text-lg">
            Monitor de emergencias en tiempo real.
          </p>
          <div className="bg-yellow-100 dark:bg-yellow-900/20 border border-yellow-200 dark:border-yellow-700/50 px-3 py-1 rounded-full">
            <p className="text-xs text-yellow-700 dark:text-yellow-500 font-semibold tracking-wide uppercase">
              Solo disponible en territorio español 🇪🇸
            </p>
          </div>
        </div>

        <div className="w-full bg-white/80 dark:bg-slate-900/50 backdrop-blur-md p-6 rounded-2xl border border-slate-200 dark:border-slate-800 shadow-xl text-left transition-colors duration-300">
          <div className="mb-6">
             <label className="flex justify-between text-xs text-slate-500 dark:text-slate-400 mb-2 font-mono uppercase tracking-wider">
                <span>Radio de cobertura</span>
                <span className="text-slate-900 dark:text-white font-bold">{radius} km</span>
             </label>
             <input 
                type="range" 
                min="5" 
                max="100" 
                step="5"
                value={radius} 
                onChange={(e) => setRadius(Number(e.target.value))}
                className="w-full h-2 bg-slate-200 dark:bg-slate-700 rounded-lg appearance-none cursor-pointer accent-blue-500 hover:accent-blue-400 transition-colors"
             />
          </div>

          <button 
            onClick={handleGPSLocation}
            disabled={loading}
            className="w-full py-4 bg-blue-600 hover:bg-blue-500 text-white rounded-xl font-bold flex items-center justify-center gap-2 transition-all active:scale-95 mb-4 group shadow-lg shadow-blue-500/20"
          >
            {loading ? <Loader2 className="animate-spin" /> : <Navigation className="w-5 h-5 group-hover:animate-pulse" />}
            Usar mi ubicación actual
          </button>

          <div className="relative flex py-2 items-center">
            <div className="flex-grow border-t border-slate-200 dark:border-slate-800"></div>
            <span className="flex-shrink mx-4 text-slate-400 dark:text-slate-500 text-xs uppercase tracking-widest">o busca tu ciudad</span>
            <div className="flex-grow border-t border-slate-200 dark:border-slate-800"></div>
          </div>

          <form onSubmit={handleManualLocation} className="mt-4 flex gap-2">
            <input 
              type="text" 
              placeholder="Ej: Toledo, Valencia, Madrid..." 
              className="flex-1 bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-700 rounded-xl px-4 py-3 text-slate-900 dark:text-white focus:outline-none focus:border-blue-500 transition-colors placeholder:text-slate-400"
              value={location.name}
              onChange={(e) => setLocation({ ...location, name: e.target.value })}
            />
            <button 
              type="submit"
              disabled={loading || !location.name}
              className="bg-slate-100 dark:bg-slate-800 hover:bg-slate-200 dark:hover:bg-slate-700 text-slate-700 dark:text-white p-3 rounded-xl transition-colors border border-slate-200 dark:border-slate-700 disabled:opacity-50"
            >
              {loading ? <Loader2 className="animate-spin w-5 h-5" /> : <Search className="w-5 h-5" />}
            </button>
          </form>

          <button 
            onClick={() => setView(ViewState.HISTORY)}
            className="w-full mt-4 py-2 text-xs text-slate-500 hover:text-slate-700 dark:hover:text-slate-300 flex items-center justify-center gap-1 transition-colors"
          >
            <History className="w-3 h-3" />
            Búsqueda histórica
          </button>
        </div>

        <div className="w-full bg-slate-100 dark:bg-slate-900/30 p-4 rounded-xl border border-slate-200 dark:border-slate-800/50 flex gap-3 text-left">
            <Info className="w-5 h-5 text-slate-400 flex-shrink-0 mt-0.5" />
            <p className="text-[11px] text-slate-500 dark:text-slate-400 leading-relaxed">
                <span className="font-bold uppercase block mb-1">Origen de los datos</span>
                Esta aplicación utiliza IA para agregar información de fuentes oficiales (AEMET, DGT, 112), noticias locales y señales sociales. 
                <span className="block mt-1">No es un canal oficial de emergencias. En caso de peligro real, siga las instrucciones de las autoridades y llame al 112.</span>
            </p>
        </div>
      </div>
    </div>
  );

  const renderHistory = () => (
    <div className="flex flex-col items-center justify-start h-screen p-6 bg-slate-50 dark:bg-slate-950 overflow-y-auto transition-colors duration-300">
      <div className="w-full max-w-md bg-white/80 dark:bg-slate-900/80 p-6 rounded-2xl border border-slate-200 dark:border-slate-800 shadow-xl backdrop-blur-md my-12">
        <div className="flex items-center gap-2 mb-6 cursor-pointer group" onClick={() => setView(ViewState.ONBOARDING)}>
          <Calendar className="w-6 h-6 text-purple-500" />
          <span className="text-xl font-bold text-slate-900 dark:text-slate-300 group-hover:text-purple-500 transition-colors">Archivo Histórico</span>
        </div>

        <form onSubmit={handleHistorySearch} className="space-y-4">
          <div>
            <label className="text-xs text-slate-500 dark:text-slate-400 uppercase font-bold mb-1 block">Ubicación</label>
            <div className="flex gap-2">
                <input 
                  type="text"
                  required
                  value={historyLocation}
                  onChange={(e) => setHistoryLocation(e.target.value)}
                  placeholder="Ciudad o región"
                  className="flex-1 bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-700 rounded-lg px-4 py-3 text-slate-900 dark:text-white focus:border-purple-500 focus:outline-none transition-colors"
                />
                <button 
                    type="button"
                    onClick={handleHistoryGPS}
                    className="bg-slate-100 dark:bg-slate-800 hover:bg-slate-200 dark:hover:bg-slate-700 text-slate-700 dark:text-white px-3 rounded-lg border border-slate-200 dark:border-slate-700 transition-colors flex items-center justify-center"
                    disabled={loading}
                >
