            {!historyDate && (
               <div className="relative flex items-center bg-slate-100 dark:bg-slate-800 rounded-full px-2 gap-1 border border-slate-200 dark:border-slate-700">
                  <div className="text-[10px] font-mono font-bold text-slate-500 dark:text-slate-400 px-1">{countdown}s</div>
                  <button
                    onClick={toggleMonitoring}
                    className={`p-1.5 rounded-full transition-all ${isMonitoring ? 'text-emergency-500' : 'text-slate-400 hover:text-slate-600 dark:hover:text-white'}`}
                    title={isMonitoring ? "Monitorización activada" : "Activar monitorización"}
                  >
                    {isMonitoring ? <Bell className="w-4 h-4 animate-pulse" /> : <BellOff className="w-4 h-4" />}
                  </button>
               </div>
            )}
             <button
                onClick={toggleTheme}
                className="p-2 rounded-full bg-slate-100 dark:bg-slate-800 text-slate-400 hover:text-slate-700 dark:hover:text-white transition-all border border-slate-200 dark:border-transparent"
             >
                {theme === 'dark' ? <Sun className="w-5 h-5" /> : <Moon className="w-5 h-5" />}
             </button>
            <button 
               onClick={refreshAlerts}
               className="p-2 bg-slate-100 dark:bg-slate-800 rounded-full text-slate-400 hover:text-slate-700 dark:hover:text-white transition-all border border-slate-200 dark:border-transparent"
            >
              <RotateCw className={`w-5 h-5 ${loading ? 'animate-spin' : ''}`} />
            </button>
             <button 
               onClick={() => {
                   setHistoryDate(''); 
                   setHistoryLocation('');
                   setView(ViewState.ONBOARDING);
                   setIsMonitoring(false);
