                        <div className="flex items-center gap-3">
                             <Calendar className="w-6 h-6 text-purple-600 dark:text-purple-400" />
                            <div>
                                <div className="text-purple-800 dark:text-purple-100 text-sm font-black uppercase tracking-tight">Archivo Histórico</div>
                                <div className="text-purple-600/70 dark:text-purple-300/70 text-xs font-medium">Visualizando eventos del {historyDate}</div>
                            </div>
                        </div>
                     </div>
