                <StatsChart events={alerts} />

                <div className="bg-white dark:bg-slate-900/60 p-5 rounded-2xl border border-slate-200 dark:border-slate-800 mb-6 relative overflow-hidden shadow-sm transition-colors group">
                    {/* Animated Radar Effect */}
                    <div className="absolute top-0 right-0 p-4 opacity-10 group-hover:opacity-20 transition-opacity">
                        <Radio className="w-16 h-16 text-blue-500 animate-ping" />
                    </div>

                    <h3 className="text-[10px] font-black text-blue-600 dark:text-blue-400 uppercase tracking-[0.2em] mb-3 flex items-center gap-2">
                        <ShieldAlert className="w-3 h-3" />
