                <div className="flex justify-between items-end mb-4 px-1">
                    <h3 className="text-lg font-black text-slate-900 dark:text-white tracking-tight">Reportes Recientes</h3>
                    <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest bg-slate-100 dark:bg-slate-800 px-2 py-0.5 rounded-full">{alerts.length} Detectados</span>
                </div>

                <div className="space-y-4">
                    {alerts.map(event => (
                        <AlertCard key={event.id} event={event} />
                    ))}
                    {alerts.length === 0 && (
                        <div className="flex flex-col items-center justify-center py-16 text-slate-400 border-2 border-dashed border-slate-200 dark:border-slate-800 rounded-3xl">
                            <ShieldCheck className="w-12 h-12 mb-3 opacity-20" />
