                    <div className="flex items-center gap-2 text-slate-400 dark:text-slate-500">
                        <Info className="w-4 h-4" />
                        <span className="text-[10px] uppercase font-black tracking-widest">Aviso de Seguridad</span>
                    </div>
                    <p className="text-[10px] text-slate-500 dark:text-slate-400 leading-relaxed max-w-[280px]">
                        Este reporte agrega datos mediante IA de fuentes oficiales y señales sociales. 
                        <strong>No sustituye a las autoridades.</strong> En emergencias, llame al 112 y siga las instrucciones oficiales.
                    </p>
                </div>
            </>
        )}
      </main>

      <div className="fixed bottom-0 w-full bg-white/95 dark:bg-slate-900/95 backdrop-blur-md border-t border-slate-200 dark:border-slate-800 p-4 text-xs text-slate-500 dark:text-slate-400 flex justify-center gap-6 z-40 max-w-2xl left-1/2 -translate-x-1/2 rounded-t-3xl transition-colors shadow-[0_-8px_30px_rgb(0,0,0,0.08)]">
          <div className="flex items-center gap-1.5 font-bold"><span className="w-2 h-2 rounded-full bg-red-500 shadow-[0_0_8px_rgba(239,68,68,0.5)]"></span> Crítico</div>
          <div className="flex items-center gap-1.5 font-bold"><span className="w-2 h-2 rounded-full bg-orange-500 shadow-[0_0_8px_rgba(249,115,22,0.5)]"></span> Aviso</div>
          <div className="flex items-center gap-1.5 font-bold"><span className="w-2 h-2 rounded-full bg-blue-500 shadow-[0_0_8px_rgba(59,130,246,0.5)]"></span> Oficial</div>
          <div className="flex items-center gap-1.5 font-bold"><span className="w-2 h-2 rounded-full bg-purple-500 shadow-[0_0_8px_rgba(139,92,246,0.5)]"></span> Social</div>
      </div>
    </div>
  );

  return (
    <>
      {view === ViewState.ONBOARDING && renderOnboarding()}
      {view === ViewState.HISTORY && renderHistory()}
      {view === ViewState.DASHBOARD && renderDashboard()}
    </>
  );
}

import { GoogleGenAI, Type } from "@google/genai";
import { AlertEvent, SeverityLevel, SourceType } from "../types";

// Always use new GoogleGenAI({ apiKey: process.env.API_KEY })
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const eventSchema = {
  type: Type.OBJECT,
  properties: {
    events: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING, description: "Título corto del evento en Español" },
          description: { type: Type.STRING, description: "Resumen detallado de lo que está ocurriendo en Español" },
          severity: { type: Type.STRING, enum: [SeverityLevel.CRITICAL, SeverityLevel.WARNING, SeverityLevel.INFO, SeverityLevel.SAFE] },
          category: { type: Type.STRING, description: "Categoría en una palabra: Incendio, Clima, Protesta, Tráfico, Seguridad, Salud, Otro" },
          sourceName: { type: Type.STRING, description: "Nombre de la fuente principal (ej. AEMET, Usuario Twitter, El País)" },
          sourceType: { type: Type.STRING, enum: [SourceType.OFFICIAL, SourceType.NEWS, SourceType.SOCIAL] },
          timeInfo: { type: Type.STRING, description: "Cuándo ocurrió (ej. 'hace 10 min', '1 Ago 14:00')" }
        },
        required: ["title", "description", "severity", "category", "sourceName", "sourceType", "timeInfo"]
      }
    },
    riskAnalysis: { type: Type.STRING, description: "Un breve resumen de 1 oración sobre el nivel general de seguridad para el usuario en Español." }
  },
  required: ["events", "riskAnalysis"]
};

export const fetchAlerts = async (
  location: string, 
  date?: string, 
  radius?: number, 
  categoryFilter?: string
): Promise<{ events: AlertEvent[], analysis: string }> => {
  const isHistorical = !!date;
  const radiusContext = radius ? ` en un radio de ${radius} kilómetros alrededor` : '';
  const categoryContext = categoryFilter && categoryFilter !== 'TODAS' 
    ? ` Céntrate EXCLUSIVAMENTE en eventos relacionados con la categoría: "${categoryFilter}" (ej. ES-Alert, Emergencias, Incendios, etc).` 
    : '';

  const systemInstruction = `
    Eres un sistema avanzado de inteligencia de emergencias para España, "Monitor de Emergencias".
    Tu trabajo es analizar eventos actuales o pasados en una ubicación específica buscando en la web, noticias y redes sociales.

    Región Objetivo: España (Exclusivamente).
    Contexto Geográfico: ${location}${radiusContext}.
    Modo: ${isHistorical ? `Archivo Histórico (Fecha: ${date})` : 'Monitoreo en Tiempo Real'}.
    ${categoryContext}

    Prioriza:
    1. Fuentes OFICIALES: AEMET (Clima), DGT (Tráfico), Policía, Guardia Civil, 112, Ayuntamientos, Protección Civil, ES-Alert.
    2. Noticias: Periódicos locales y nacionales (El País, El Mundo, prensa local).
    3. Señales SOCIALES: Tendencias en redes que indiquen disturbios, incendios, accidentes o quejas ciudadanas.

    Clasifica la 'severidad' estrictamente:
    - CRITICAL: Amenaza la vida (Inundaciones, incendios mayores, disturbios violentos, terrorismo, alertas rojas AEMET).
    - WARNING: Disrupción significativa (Alertas de lluvia intensa, protestas, accidentes de tráfico graves).
    - INFO: Actualizaciones generales, retrasos menores, obras, eventos culturales.
    - SAFE: No se encontraron problemas importantes (indica explícitamente si el área está tranquila).

    IDIOMA: Todo el contenido generado (título, descripción, análisis) DEBE estar en ESPAÑOL.

    Si no se encuentran eventos, devuelve un evento SAFE indicando "No se reportan incidentes significativos".
  `;

  const userPrompt = isHistorical 
    ? `Busca eventos que ocurrieron en ${location} el día ${date}. Busca en archivos de noticias, publicaciones de redes sociales de esa fecha e informes oficiales.${categoryContext}`
    : `Encuentra emergencias EN VIVO, advertencias o noticias de última hora en ${location}${radiusContext} ahora mismo. Revisa AEMET para el clima, DGT para el tráfico y busca conversaciones recientes en redes sociales sobre incidentes.${categoryContext}`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: userPrompt,
      config: {
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
        responseSchema: eventSchema,
        systemInstruction: systemInstruction,
      },
    });

    const resultText = response.text;
    if (!resultText) throw new Error("No response from AI");

    const parsedData = JSON.parse(resultText);

    // Process grounding chunks to attach real URLs if available
    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];

    const events: AlertEvent[] = parsedData.events.map((evt: any, index: number) => {
      // Attempt to find a relevant link from grounding chunks
      let relevantLink = '';
      if (groundingChunks.length > 0) {
        // Simple heuristic
        const chunk = groundingChunks[index % groundingChunks.length];
        if (chunk?.web?.uri) {
            relevantLink = chunk.web.uri;
        }
      }

      // Generate a deterministic ID based on content
      const idString = `${evt.title}-${evt.timeInfo}-${location}`;
      let hash = 0;
      for (let i = 0; i < idString.length; i++) {
        const char = idString.charCodeAt(i);
        hash = ((hash << 5) - hash) + char;
        hash = hash & hash; // Convert to 32bit integer
      }
      const deterministicId = `evt-${Math.abs(hash)}`;

      return {
        id: deterministicId,
        title: evt.title,
        description: evt.description,
        location: location,
        timestamp: evt.timeInfo,
        severity: evt.severity as SeverityLevel,
        category: evt.category,
        isHistorical: isHistorical,
        sources: [{
          name: evt.sourceName,
          type: evt.sourceType as SourceType,
          url: relevantLink
        }]
      };
    });

    return {
      events,
      analysis: parsedData.riskAnalysis || "Análisis completo."
    };

  } catch (error) {
    console.error("Gemini API Error:", error);
    return {
      events: [{
        id: 'error-offline',
        title: 'Sistema Desconectado',
        description: 'No se pueden recuperar datos en este momento. Por favor verifique la conexión.',
        location: location,
        timestamp: 'Ahora',
        severity: SeverityLevel.INFO,
        category: 'Sistema',
        sources: []
      }],
      analysis: "El sistema no pudo realizar el análisis."
    };
  }
};

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { MapPin, Navigation, Search, History, AlertOctagon, RotateCw, Loader2, Bell, BellOff, Calendar, Filter, Sun, Moon, Info, ShieldAlert, Radio, ShieldCheck } from 'lucide-react';
import { AlertEvent, UserLocation, SeverityLevel } from './types';
import { fetchAlerts } from './services/geminiService';
import AlertCard from './components/AlertCard';
import StatsChart from './components/StatsChart';

enum ViewState {
  ONBOARDING,
  DASHBOARD,
  HISTORY
}

export default function App() {
  const [view, setView] = useState<ViewState>(ViewState.ONBOARDING);
  const [location, setLocation] = useState<UserLocation>({ name: '', isGPS: false });
  const [alerts, setAlerts] = useState<AlertEvent[]>([]);
  const [analysis, setAnalysis] = useState<string>('');
  const [loading, setLoading] = useState(false);
  const [radius, setRadius] = useState<number>(10); // Default 10km
  const [countdown, setCountdown] = useState(60);

  // Theme State
  const [theme, setTheme] = useState<'light' | 'dark'>(() => {
    if (typeof window !== 'undefined') {
        const saved = localStorage.getItem('theme');
        return (saved === 'light' || saved === 'dark') ? saved : 'dark';
    }
    return 'dark';
  });

  // Apply Theme
  useEffect(() => {
    const root = window.document.documentElement;
    if (theme === 'dark') {
        root.classList.add('dark');
    } else {
        root.classList.remove('dark');
    }
    localStorage.setItem('theme', theme);
  }, [theme]);

  const toggleTheme = () => setTheme(prev => prev === 'dark' ? 'light' : 'dark');

  // History Mode State - Active query
  const [historyDate, setHistoryDate] = useState<string>('');
  const [activeHistoryCategory, setActiveHistoryCategory] = useState<string>('');

  // History Form State
  const [historyLocation, setHistoryLocation] = useState<string>('');
  const [formDay, setFormDay] = useState<number>(new Date().getDate());
  const [formMonth, setFormMonth] = useState<number>(new Date().getMonth()); // 0-11
  const [formYear, setFormYear] = useState<number>(new Date().getFullYear());
  const [formCategory, setFormCategory] = useState<string>('TODAS');

  // Notification & Real-time State
  const [isMonitoring, setIsMonitoring] = useState(false);
  const [permission, setPermission] = useState<NotificationPermission>('default');
  const seenAlertsRef = useRef<Set<string>>(new Set());

  useEffect(() => {
    if ('Notification' in window) {
      setPermission(Notification.permission);
    }
  }, []);

  const requestNotificationPermission = async () => {
    if (!('Notification' in window)) {
      alert('Este navegador no soporta notificaciones.');
      return;
    }
    const result = await Notification.requestPermission();
    setPermission(result);
    if (result === 'granted') {
      setIsMonitoring(true);
      new Notification('Alertas Activas', {
        body: `Monitorización en tiempo real activada para ${location.name}.`,
        icon: '/favicon.ico'
      });
    }
  };

  const toggleMonitoring = () => {
    if (isMonitoring) {
      setIsMonitoring(false);
    } else {
      if (permission === 'granted') {
        setIsMonitoring(true);
      } else {
        requestNotificationPermission();
      }
    }
  };

  const checkAndNotify = (newAlerts: AlertEvent[]) => {
    if (permission !== 'granted' || !isMonitoring) return;

    newAlerts.forEach(alert => {
      if ((alert.severity === SeverityLevel.CRITICAL || alert.severity === SeverityLevel.WARNING) && 
          !seenAlertsRef.current.has(alert.id)) {

        seenAlertsRef.current.add(alert.id);

        new Notification(`⚠️ ${alert.severity}: ${alert.title}`, {
          body: alert.description,
          tag: alert.id,
          requireInteraction: alert.severity === SeverityLevel.CRITICAL
        });
      }
    });
  };

  // Background Polling and Countdown Effect
  useEffect(() => {
    if (view !== ViewState.DASHBOARD || historyDate || !isMonitoring || !location.name) {
      setCountdown(60);
      return;
    }

    const timer = setInterval(() => {
      setCountdown(prev => {
        if (prev <= 1) {
          refreshAlerts();
          return 60;
        }
        return prev - 1;
      });
    }, 1000);

    return () => clearInterval(timer);
  }, [view, historyDate, isMonitoring, location.name]);

  const refreshAlerts = async () => {
    try {
      const result = await fetchAlerts(location.name, undefined, radius);
      setAlerts(result.events);
      setAnalysis(result.analysis);
      checkAndNotify(result.events);
    } catch (e) {
      console.error("Refresh failed", e);
    }
  };


  const handleGPSLocation = () => {
    setLoading(true);
    if ('geolocation' in navigator) {
      navigator.geolocation.getCurrentPosition(
        async (position) => {
          const lat = position.coords.latitude.toFixed(4);
          const lng = position.coords.longitude.toFixed(4);

          setLocation({ lat: position.coords.latitude, lng: position.coords.longitude, name: `GPS: ${lat}, ${lng}`, isGPS: true });
          await executeSearch(`Coordenadas ${lat}, ${lng} España`, undefined, radius);
        },
        (error) => {
          console.error("GPS Error", error);
          setLoading(false);
          alert("No se pudo obtener el GPS. Por favor introduzca la ubicación manualmente.");
        }
      );
    } else {
      setLoading(false);
      alert("Geolocalización no soportada.");
    }
  };

  const handleHistoryGPS = () => {
    setLoading(true);
    if ('geolocation' in navigator) {
      navigator.geolocation.getCurrentPosition(
        (position) => {
          const lat = position.coords.latitude.toFixed(4);
          const lng = position.coords.longitude.toFixed(4);
          setHistoryLocation(`Coordenadas GPS: ${lat}, ${lng}`);
          setLoading(false);
        },
        (error) => {
          console.error("GPS Error", error);
          setLoading(false);
          alert("No se pudo obtener el GPS.");
        }
      );
    } else {
      setLoading(false);
      alert("Geolocalización no soportada.");
    }
  };

  const handleManualLocation = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!location.name) return;
    await executeSearch(location.name);
  };

  const executeSearch = async (locName: string, date?: string, searchRadius?: number, category?: string) => {
    setLoading(true);
    setCountdown(60);
    seenAlertsRef.current.clear();

    const effectiveRadius = searchRadius || radius;

    const result = await fetchAlerts(locName, date, effectiveRadius, category);
    setAlerts(result.events);
    setAnalysis(result.analysis);

    if (isMonitoring) {
        checkAndNotify(result.events);
    }

    if (!location.name || location.name.startsWith('GPS')) {
       setLocation(prev => ({ ...prev, name: locName }));
    }

    setLoading(false);
    setView(ViewState.DASHBOARD);
  };

  const handleHistorySearch = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!historyLocation) return;

    const mm = (formMonth + 1).toString().padStart(2, '0');
    const dd = formDay.toString().padStart(2, '0');
    const dateStr = `${formYear}-${mm}-${dd}`;

    setHistoryDate(dateStr);
    setActiveHistoryCategory(formCategory);

    setLoading(true);
    const result = await fetchAlerts(historyLocation, dateStr, undefined, formCategory);
    setAlerts(result.events);
    setAnalysis(result.analysis);
    setLocation({ name: historyLocation, isGPS: false });
    setIsMonitoring(false);
    setView(ViewState.DASHBOARD); 
    setLoading(false);
  };

  const months = [
    "Enero", "Febrero", "Marzo", "Abril", "Mayo", "Junio", 
    "Julio", "Agosto", "Septiembre", "Octubre", "Noviembre", "Diciembre"
  ];
  const currentYear = new Date().getFullYear();
  const years = Array.from({length: 30}, (_, i) => currentYear - i);
  const daysInMonth = new Date(formYear, formMonth + 1, 0).getDate();
  const days = Array.from({length: daysInMonth}, (_, i) => i + 1);

  const categories = [
    "TODAS", "Emergencias 112", "ES-Alert", "Incendios", "Clima / AEMET", "Tráfico / DGT", "Seguridad Ciudadana"
  ];

  const renderOnboarding = () => (
    <div className="flex flex-col items-center justify-start h-screen p-6 bg-slate-50 dark:bg-slate-950 relative overflow-y-auto transition-colors duration-300">
