import { GoogleGenAI, Type } from "@google/genai";
import { AlertEvent, SeverityLevel, SourceType } from "../types";

// Inicialización siguiendo estrictamente las guías
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Nota técnica: Las guías prohíben parsear JSON directamente de una respuesta con googleSearch.
 * Implementamos un flujo de dos pasos: 
 * 1. Búsqueda y recopilación de información bruta.
 * 2. Estructuración de esa información en JSON.
 */

export const fetchAlerts = async (
  location: string, 
  date?: string, 
  radius?: number, 
  categoryFilter?: string
): Promise<{ events: AlertEvent[], analysis: string }> => {
  const isHistorical = !!date;
  const radiusContext = radius ? ` en un radio de ${radius} kilómetros` : '';
  const categoryContext = categoryFilter && categoryFilter !== 'TODAS' 
    ? ` filtrando por la categoría "${categoryFilter}"` 
    : '';

  const searchPrompt = isHistorical 
    ? `Lista todas las emergencias, avisos de tráfico, incendios, alertas climáticas y sucesos importantes ocurridos en ${location}${radiusContext} el día ${date}${categoryContext}. Incluye fuentes y detalles específicos de AEMET, DGT y prensa local.`
    : `Lista todas las emergencias EN VIVO, alertas de AEMET (clima), incidencias de la DGT (tráfico), incendios activos y noticias de última hora en ${location}${radiusContext} ahora mismo. Incluye tendencias en redes sociales y fuentes oficiales.`;

  try {
    // PASO 1: Búsqueda de información
    const searchResponse = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: searchPrompt,
      config: {
        tools: [{ googleSearch: {} }],
        thinkingConfig: { thinkingBudget: 0 }
      },
    });

    const rawInfo = searchResponse.text || "No se encontró información relevante.";
    const chunks = searchResponse.candidates?.[0]?.groundingMetadata?.groundingChunks || [];

    // PASO 2: Estructuración en JSON (sin herramientas para permitir responseMimeType)
    const structuringPrompt = `
      Basándote en la siguiente información de búsqueda, genera un objeto JSON con las emergencias detectadas en España.

      INFORMACIÓN:
      ${rawInfo}

      INSTRUCCIONES:
      - Clasifica la severidad como CRITICAL, WARNING, INFO o SAFE.
      - Si no hay nada grave, crea al menos un evento SAFE.
      - Idioma: Español.
    `;

    const structResponse = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: structuringPrompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            events: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  title: { type: Type.STRING },
                  description: { type: Type.STRING },
                  severity: { type: Type.STRING, enum: ['CRITICAL', 'WARNING', 'INFO', 'SAFE'] },
                  category: { type: Type.STRING },
                  sourceName: { type: Type.STRING },
                  timeInfo: { type: Type.STRING }
                },
                required: ["title", "description", "severity", "category", "sourceName", "timeInfo"]
              }
            },
            riskAnalysis: { type: Type.STRING }
          },
          required: ["events", "riskAnalysis"]
        }
      }
    });

    const parsedData = JSON.parse(structResponse.text || '{"events":[], "riskAnalysis":""}');

    const events: AlertEvent[] = parsedData.events.map((evt: any, index: number) => {
      // Extraemos URLs de los chunks de búsqueda si coinciden o simplemente las rotamos
      const sourceUrl = chunks[index % chunks.length]?.web?.uri || '';

      const idString = `${evt.title}-${evt.timeInfo}-${location}`;
      let hash = 0;
      for (let i = 0; i < idString.length; i++) {
        hash = ((hash << 5) - hash) + idString.charCodeAt(i);
        hash |= 0;
      }

      return {
        id: `evt-${Math.abs(hash)}`,
        title: evt.title,
        description: evt.description,
        location: location,
        timestamp: evt.timeInfo,
        severity: evt.severity as SeverityLevel,
        category: evt.category,
        isHistorical: isHistorical,
        sources: [{
          name: evt.sourceName,
          type: sourceUrl.includes('twitter') || sourceUrl.includes('t.co') ? SourceType.SOCIAL : SourceType.OFFICIAL,
          url: sourceUrl
        }]
      };
    });

    return {
      events,
      analysis: parsedData.riskAnalysis || "Monitorización completada con éxito."
    };

  } catch (error) {
    console.error("Error en GeminiService:", error);
    throw error;
  }
};

