          </div>

          <div className="grid gap-4">
            <button onClick={handleGPSLocation} disabled={loading} className="w-full py-5 bg-slate-900 dark:bg-blue-600 hover:bg-slate-800 dark:hover:bg-blue-500 text-white rounded-2xl font-black flex items-center justify-center gap-3 transition-all active:scale-95 shadow-xl shadow-blue-500/10 uppercase tracking-widest text-sm">
