           <footer className="fixed bottom-0 left-0 right-0 p-6 pointer-events-none">
              <div className="max-w-3xl mx-auto flex justify-center">
                  <div className="bg-white/90 dark:bg-slate-900/90 backdrop-blur-xl border border-slate-200 dark:border-slate-800 px-6 py-3 rounded-full shadow-2xl pointer-events-auto flex items-center gap-6 text-[10px] font-black uppercase tracking-widest text-slate-400">
                      <div className="flex items-center gap-2"><span className="w-2 h-2 rounded-full bg-red-500 shadow-sm shadow-red-500"></span> Crítico</div>
                      <div className="flex items-center gap-2"><span className="w-2 h-2 rounded-full bg-orange-500 shadow-sm shadow-orange-500"></span> Aviso</div>
