import { GoogleGenAI, Type } from "@google/genai";
import { AlertEvent, SeverityLevel, SourceType } from "../types";

// Inicialización del cliente de IA
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Servicio de monitorización de emergencias que utiliza un proceso de dos pasos:
 * 1. Grounding: Búsqueda de información fresca mediante Google Search.
 * 2. Estructuración: Análisis y clasificación de la información en un esquema JSON estricto.
 */
export const fetchAlerts = async (
  location: string, 
  date?: string, 
  radius?: number, 
  categoryFilter?: string
): Promise<{ events: AlertEvent[], analysis: string }> => {
  const isHistorical = !!date;
  const radiusContext = radius ? ` en un radio de ${radius} kilómetros` : '';
  const categoryContext = categoryFilter && categoryFilter !== 'TODAS' 
    ? ` filtrando por la categoría "${categoryFilter}"` 
    : '';

  // Prompt optimizado para España (fuentes locales y oficiales)
  const searchPrompt = isHistorical 
    ? `Lista todas las emergencias, avisos de tráfico, incendios forestales, alertas climáticas de AEMET y sucesos importantes ocurridos en ${location}${radiusContext} el día ${date}${categoryContext}. Proporciona detalles específicos y cita fuentes como el 112 regional, la DGT o diarios locales.`
    : `Escaneo en tiempo real: Detecta emergencias activas, alertas naranjas/rojas de AEMET, cortes de carretera de la DGT, incendios forestales y sucesos de seguridad ciudadana en ${location}${radiusContext} AHORA MISMO. Cita fuentes oficiales españolas.`;

  try {
    // PASO 1: Búsqueda y recopilación (Grounding)
    const searchResponse = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: searchPrompt,
      config: {
        tools: [{ googleSearch: {} }],
        thinkingConfig: { thinkingBudget: 0 }
      },
    });

    const rawInfo = searchResponse.text || "Situación estable. No se han detectado incidentes significativos.";
    const chunks = searchResponse.candidates?.[0]?.groundingMetadata?.groundingChunks || [];

    // PASO 2: Estructuración y Razonamiento (Pro Model para mayor precisión)
    const structuringPrompt = `
      Actúa como un analista de Protección Civil en España.
      Analiza la siguiente información de búsqueda y estructúrala en un objeto JSON válido.

      INFORMACIÓN DE BÚSQUEDA:
      ${rawInfo}

      REGLAS DE SALIDA:
      - severity: CRITICAL (riesgo vida/propiedad), WARNING (precaución necesaria), INFO (informativo), SAFE (sin riesgo).
      - category: Incendios, Clima, Tráfico, Seguridad, Salud o General.
      - timeInfo: Hora aproximada o "Reciente".
      - riskAnalysis: Un párrafo resumen de la situación general en la zona.
      - Idioma: Español profesional.
    `;

    const structResponse = await ai.models.generateContent({
      model: 'gemini-3-pro-preview', // Upgrade a Pro para el análisis crítico
      contents: structuringPrompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            events: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  title: { type: Type.STRING },
                  description: { type: Type.STRING },
                  severity: { type: Type.STRING, enum: ['CRITICAL', 'WARNING', 'INFO', 'SAFE'] },
                  category: { type: Type.STRING },
                  sourceName: { type: Type.STRING },
                  timeInfo: { type: Type.STRING }
                },
                required: ["title", "description", "severity", "category", "sourceName", "timeInfo"]
              }
            },
            riskAnalysis: { type: Type.STRING }
          },
          required: ["events", "riskAnalysis"]
        }
      }
    });

    const parsedData = JSON.parse(structResponse.text || '{"events":[], "riskAnalysis":"No se pudo procesar el análisis."}');

    const events: AlertEvent[] = parsedData.events.map((evt: any, index: number) => {
      // Intentamos asociar una URL real de la búsqueda a cada evento
      const sourceUrl = chunks[index % chunks.length]?.web?.uri || '';

      const idString = `${evt.title}-${evt.timeInfo}-${location}`;
      let hash = 0;
      for (let i = 0; i < idString.length; i++) {
        hash = ((hash << 5) - hash) + idString.charCodeAt(i);
        hash |= 0;
      }

      return {
        id: `evt-${Math.abs(hash)}`,
        title: evt.title,
        description: evt.description,
        location: location,
        timestamp: evt.timeInfo,
        severity: evt.severity as SeverityLevel,
        category: evt.category,
        isHistorical: isHistorical,
        sources: [{
          name: evt.sourceName,
          type: (sourceUrl.includes('twitter.com') || sourceUrl.includes('x.com')) ? SourceType.SOCIAL : SourceType.OFFICIAL,
          url: sourceUrl
        }]
      };
    });

    return {
      events,
      analysis: parsedData.riskAnalysis
    };

  } catch (error) {
    console.error("GeminiService Error:", error);
    throw error;
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { 
  MapPin, Navigation, Search, History, AlertOctagon, RotateCw, Loader2, 
  Bell, BellOff, Sun, Moon, Info, ShieldAlert, Radio, ShieldCheck, Siren, 
  ArrowLeft, Clock, Activity 
} from 'lucide-react';
import { AlertEvent, UserLocation, SeverityLevel } from './types';
import { fetchAlerts } from './services/geminiService';
import { AudioService } from './services/audioService';
import AlertCard from './components/AlertCard';
import StatsChart from './components/StatsChart';

enum ViewState { ONBOARDING, DASHBOARD, HISTORY }

export default function App() {
  const [view, setView] = useState<ViewState>(ViewState.ONBOARDING);
  const [location, setLocation] = useState<UserLocation>({ name: '', isGPS: false });
  const [alerts, setAlerts] = useState<AlertEvent[]>([]);
  const [analysis, setAnalysis] = useState<string>('');
  const [loading, setLoading] = useState(false);
  const [radius, setRadius] = useState<number>(10);
  const [countdown, setCountdown] = useState(60);
  const [lastUpdate, setLastUpdate] = useState<string>('');
  const [permission, setPermission] = useState<NotificationPermission>('default');

  const [theme, setTheme] = useState<'light' | 'dark'>(() => {
    if (typeof window !== 'undefined') {
        const saved = localStorage.getItem('theme');
        return (saved === 'light' || saved === 'dark') ? saved : 'dark';
    }
    return 'dark';
  });

  useEffect(() => {
    const root = window.document.documentElement;
    if (theme === 'dark') root.classList.add('dark');
    else root.classList.remove('dark');
    localStorage.setItem('theme', theme);
  }, [theme]);

  useEffect(() => {
    if ('Notification' in window) setPermission(Notification.permission);
  }, []);

  const toggleTheme = () => setTheme(prev => prev === 'dark' ? 'light' : 'dark');

  const [historyDate, setHistoryDate] = useState<string>('');
  const [historyLocation, setHistoryLocation] = useState<string>('');
  const [formDay, setFormDay] = useState<number>(new Date().getDate());
  const [formMonth, setFormMonth] = useState<number>(new Date().getMonth());
  const [formYear, setFormYear] = useState<number>(new Date().getFullYear());
  const [formCategory, setFormCategory] = useState<string>('TODAS');

  const [isMonitoring, setIsMonitoring] = useState(false);

  useEffect(() => {
    if (view !== ViewState.DASHBOARD || historyDate || !isMonitoring || !location.name) {
      setCountdown(60);
      return;
    }
    const timer = setInterval(() => {
      setCountdown(prev => {
        if (prev <= 1) { refreshAlerts(); return 60; }
        return prev - 1;
      });
    }, 1000);
    return () => clearInterval(timer);
  }, [view, historyDate, isMonitoring, location.name]);

  const requestNotificationPermission = async () => {
    if (!('Notification' in window)) return;
    const result = await Notification.requestPermission();
    setPermission(result);
    if (result === 'granted') {
      setIsMonitoring(true);
      new Notification('Monitor Activado', { 
        body: `Rastreo activo para ${location.name}. Recibirás alertas críticas.`, 
        icon: 'https://cdn-icons-png.flaticon.com/512/564/564619.png' 
      });
    }
  };

  const toggleMonitoring = () => {
    if (isMonitoring) {
      setIsMonitoring(false);
    } else {
      if (permission === 'granted') {
        setIsMonitoring(true);
      } else {
        requestNotificationPermission();
      }
    }
  };

  const refreshAlerts = async () => {
    try {
      AudioService.playScan();
      const result = await fetchAlerts(location.name, undefined, radius);
      setAlerts(result.events);
      setAnalysis(result.analysis);
      setLastUpdate(new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', second: '2-digit' }));
      if (result.events.length > 0) AudioService.playSuccess();
    } catch (e) { console.error("Refresh error:", e); }
  };

  const handleGPSLocation = () => {
    setLoading(true);
    AudioService.playScan();
    if ('geolocation' in navigator) {
      navigator.geolocation.getCurrentPosition(
        async (pos) => {
          const locName = `${pos.coords.latitude.toFixed(3)}, ${pos.coords.longitude.toFixed(3)}`;
          setLocation({ lat: pos.coords.latitude, lng: pos.coords.longitude, name: `GPS: ${locName}`, isGPS: true });
          await executeSearch(`España cerca de ${locName}`, undefined, radius);
        },
        () => { setLoading(false); alert("Error al obtener ubicación GPS. Introduce una ciudad manualmente."); }
      );
    }
  };

  const executeSearch = async (locName: string, date?: string, searchRadius?: number, category?: string) => {
    setLoading(true);
    setCountdown(60);
    try {
      const result = await fetchAlerts(locName, date, searchRadius || radius, category);
      setAlerts(result.events);
      setAnalysis(result.analysis);
      setLastUpdate(new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }));
      if (!location.name || location.name.includes('GPS')) setLocation(p => ({ ...p, name: locName }));
      AudioService.playSuccess();
      setView(ViewState.DASHBOARD);
    } catch (e) { 
      alert("Error de conexión con la IA. Por favor, inténtalo de nuevo."); 
    } finally { 
      setLoading(false); 
    }
  };

  const handleManualLocation = (e: React.FormEvent) => {
    e.preventDefault();
    if (location.name.trim()) executeSearch(location.name);
  };

  const handleHistorySearch = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!historyLocation) return;
    const mm = (formMonth + 1).toString().padStart(2, '0');
    const dd = formDay.toString().padStart(2, '0');
    const dateStr = `${formYear}-${mm}-${dd}`;
    setHistoryDate(dateStr);
    await executeSearch(historyLocation, dateStr, undefined, formCategory);
  };

  const months = ["Enero", "Febrero", "Marzo", "Abril", "Mayo", "Junio", "Julio", "Agosto", "Septiembre", "Octubre", "Noviembre", "Diciembre"];
  const currentYear = new Date().getFullYear();
  const years = Array.from({length: 30}, (_, i) => currentYear - i);

  const renderOnboarding = () => (
    <div className="flex flex-col items-center justify-start h-screen p-6 bg-slate-50 dark:bg-slate-950 relative overflow-y-auto bg-grid">
      <div className="absolute inset-0 bg-gradient-to-b from-transparent via-slate-50/50 to-slate-50 dark:via-slate-950/50 dark:to-slate-950 pointer-events-none"></div>

      <button onClick={toggleTheme} aria-label="Cambiar tema" className="absolute top-6 right-6 p-3 rounded-2xl bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 shadow-xl z-50 transition-transform active:scale-90">
        {theme === 'dark' ? <Sun className="w-5 h-5 text-yellow-500" /> : <Moon className="w-5 h-5 text-slate-700" />}
      </button>

      <div className="z-10 w-full max-w-md space-y-12 py-16 animate-in">
        <div className="flex flex-col items-center gap-8">
          <div className="relative">
             <div className="absolute inset-0 bg-blue-500/20 blur-3xl rounded-full scale-150 animate-pulse"></div>
             <div className="relative w-32 h-32 bg-white dark:bg-slate-900 rounded-[2.5rem] shadow-2xl border border-slate-100 dark:border-slate-800 flex items-center justify-center overflow-hidden">
                <ShieldAlert className="w-16 h-16 text-red-600 absolute z-10" />
                <div className="absolute inset-0 border-2 border-dashed border-slate-200 dark:border-slate-800 rounded-[2.5rem] animate-spin-slow opacity-50"></div>
                <Radio className="w-24 h-24 text-blue-500/10 animate-ping" />
             </div>
             <div className="absolute -bottom-2 -right-2 bg-emerald-500 p-2 rounded-xl shadow-lg border-4 border-white dark:border-slate-950">
                <ShieldCheck className="w-4 h-4 text-white" />
             </div>
          </div>
          <div className="text-center space-y-3">
             <h1 className="text-5xl font-black tracking-tight text-slate-900 dark:text-white uppercase leading-[0.9]">Monitor <br/> <span className="text-blue-600 dark:text-blue-500">España</span></h1>
             <p className="text-slate-400 dark:text-slate-500 font-bold uppercase tracking-[0.3em] text-[10px]">IA de Seguridad Pública</p>
          </div>
        </div>

        <div className="bg-white/90 dark:bg-slate-900/90 backdrop-blur-2xl p-8 rounded-[2.5rem] border border-slate-200 dark:border-slate-800 shadow-2xl space-y-8">
          <div className="space-y-4">
             <div className="flex justify-between text-[10px] font-black text-slate-400 uppercase tracking-widest px-1">
                <span>Rango de Análisis</span>
