import { GoogleGenAI, Type } from "@google/genai";
import { AlertEvent, SeverityLevel, SourceType } from "../types";

// Inicialización del cliente de IA
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Servicio de monitorización de emergencias optimizado.
 * Realiza una búsqueda real y luego utiliza IA para mapear quirúrgicamente
 * cada evento con su URL de origen correspondiente.
 */
export const fetchAlerts = async (
  location: string, 
  date?: string, 
  radius?: number, 
  categoryFilter?: string
): Promise<{ events: AlertEvent[], analysis: string }> => {
  const isHistorical = !!date;
  const radiusContext = radius ? ` en un radio de ${radius} kilómetros` : '';
  const categoryContext = categoryFilter && categoryFilter !== 'TODAS' 
    ? ` filtrando por la categoría "${categoryFilter}"` 
    : '';

  const searchPrompt = isHistorical 
    ? `Busca emergencias, incidentes de tráfico, incendios y alertas climáticas en ${location}${radiusContext} el día ${date}${categoryContext}. Cita fuentes oficiales y noticias de ese día exacto.`
    : `Detecta alertas activas de AEMET, DGT, incendios y emergencias 112 en ${location}${radiusContext} AHORA. Prioriza fuentes oficiales españolas.`;

  try {
    // PASO 1: Búsqueda con Grounding
    const searchResponse = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: searchPrompt,
      config: {
        tools: [{ googleSearch: {} }],
      },
    });

    const rawInfo = searchResponse.text || "";
    // Extraemos todas las fuentes encontradas por Google Search
    const groundingSources = searchResponse.candidates?.[0]?.groundingMetadata?.groundingChunks
      ?.map(chunk => ({
        title: chunk.web?.title || "Fuente",
        uri: chunk.web?.uri || ""
      })).filter(s => s.uri) || [];

    // PASO 2: Estructuración con Verificación de Enlaces
    const structuringPrompt = `
      Analiza la información de búsqueda y las fuentes proporcionadas para generar un informe de emergencias.

      INFORMACIÓN:
      ${rawInfo}

      FUENTES DISPONIBLES (URLs):
      ${groundingSources.map(s => `- ${s.title}: ${s.uri}`).join('\n')}

      INSTRUCCIONES CRÍTICAS:
      1. Para cada evento, selecciona ÚNICAMENTE la URL de la lista anterior que hable específicamente de ese suceso.
      2. Si no hay una URL específica para un evento, deja "sourceUrl" vacío. No inventes ni asignes URLs al azar.
      3. Clasifica la severidad (CRITICAL, WARNING, INFO, SAFE).
    `;

    const structResponse = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: structuringPrompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            events: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  title: { type: Type.STRING },
                  description: { type: Type.STRING },
                  severity: { type: Type.STRING, enum: ['CRITICAL', 'WARNING', 'INFO', 'SAFE'] },
                  category: { type: Type.STRING },
                  sourceName: { type: Type.STRING },
                  sourceUrl: { type: Type.STRING },
                  timeInfo: { type: Type.STRING }
                },
                required: ["title", "description", "severity", "category", "sourceName", "sourceUrl", "timeInfo"]
              }
            },
            riskAnalysis: { type: Type.STRING }
          },
          required: ["events", "riskAnalysis"]
        }
      }
    });

    const parsedData = JSON.parse(structResponse.text || '{"events":[], "riskAnalysis":""}');

    const events: AlertEvent[] = parsedData.events.map((evt: any) => {
      const idString = `${evt.title}-${evt.timeInfo}-${location}`;
      let hash = 0;
      for (let i = 0; i < idString.length; i++) {
        hash = ((hash << 5) - hash) + idString.charCodeAt(i);
        hash |= 0;
      }

      return {
        id: `evt-${Math.abs(hash)}`,
        title: evt.title,
        description: evt.description,
        location: location,
        timestamp: evt.timeInfo,
        severity: evt.severity as SeverityLevel,
        category: evt.category,
        isHistorical: isHistorical,
        sources: [{
          name: evt.sourceName,
          type: (evt.sourceUrl.includes('112') || evt.sourceUrl.includes('gob.es') || evt.sourceUrl.includes('aemet')) ? SourceType.OFFICIAL : SourceType.NEWS,
          url: evt.sourceUrl
        }]
      };
    });

    return {
      events,
      analysis: parsedData.riskAnalysis || "Análisis no disponible."
    };

  } catch (error) {
    console.error("Error en fetchAlerts:", error);
    return { events: [], analysis: "Error al sincronizar con el centro de datos." };
  }
};

