                              <span className="text-[10px] font-bold text-blue-600 bg-blue-500/10 px-3 py-1 rounded-full uppercase">{alerts.length} Reportes</span>
                           </div>
                           {alerts.map(evt => <AlertCard key={evt.id} event={evt} />)}
                           {alerts.length === 0 && (
                               <div className="py-20 flex flex-col items-center justify-center border-2 border-dashed border-slate-200 dark:border-slate-800 rounded-[2.5rem] opacity-30">
                                   <ShieldCheck className="w-12 h-12 mb-4" />
                                   <p className="text-xs font-black uppercase tracking-widest">Sin Incidentes Relevantes</p>
                               </div>
                           )}
                        </div>
                    </>
                )}
             </div>
           </main>
           <footer className="fixed bottom-0 left-0 right-0 p-6 pointer-events-none">
              <div className="max-w-3xl mx-auto flex justify-center">
                  <div className="bg-white/90 dark:bg-slate-900/95 backdrop-blur-xl border border-slate-200 dark:border-slate-800 px-6 py-4 rounded-[2rem] shadow-2xl pointer-events-auto flex items-center gap-8 text-[10px] font-black uppercase tracking-widest text-slate-500">
                      <div className="flex items-center gap-2"><div className="w-2.5 h-2.5 rounded-full bg-red-500 animate-pulse shadow-[0_0_8px_red]"></div> CRÍTICO</div>
                      <div className="flex items-center gap-2"><div className="w-2.5 h-2.5 rounded-full bg-orange-500"></div> AVISO</div>
                      <div className="flex items-center gap-2 text-blue-500"><Activity className="w-3.5 h-3.5" /> LIVE MONITOR</div>
                  </div>
              </div>
           </footer>
        </div>
      )}
    </div>
  );
}

import { GoogleGenAI, Type } from "@google/genai";
import { AlertEvent, SeverityLevel, SourceType } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Servicio de monitorización de emergencias con mapeo de fuentes por índice.
 * Este método garantiza que el enlace mostrado corresponda exactamente al evento detectado.
 */
export const fetchAlerts = async (
  location: string, 
  date?: string, 
  radius?: number, 
  categoryFilter?: string
): Promise<{ events: AlertEvent[], analysis: string }> => {
  const isHistorical = !!date;
  const radiusContext = radius ? ` en un radio de ${radius} kilómetros` : '';
  const categoryContext = categoryFilter && categoryFilter !== 'TODAS' 
    ? ` filtrando por la categoría "${categoryFilter}"` 
    : '';

  const searchPrompt = isHistorical 
    ? `Busca reportes de emergencias, tráfico, incendios y alertas climáticas en ${location}${radiusContext} el día ${date}${categoryContext}. Cita fuentes oficiales españolas y noticias locales de ese día exacto.`
    : `Detecta alertas ACTIVAS de AEMET, DGT, incendios y emergencias 112 en ${location}${radiusContext} AHORA. Prioriza fuentes oficiales españolas y medios de comunicación locales.`;

  try {
    // PASO 1: Búsqueda con Grounding (Flash para velocidad)
    const searchResponse = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: searchPrompt,
      config: {
        tools: [{ googleSearch: {} }],
      },
    });

    const rawInfo = searchResponse.text || "";
    const groundingSources = searchResponse.candidates?.[0]?.groundingMetadata?.groundingChunks
      ?.map((chunk, index) => ({
        id: index,
        title: chunk.web?.title || "Enlace de interés",
        uri: chunk.web?.uri || ""
      })).filter(s => s.uri) || [];

    // PASO 2: Estructuración y Mapeo por Índice (Pro para precisión extrema)
    const structuringPrompt = `
      Actúa como un analista de emergencias. Procesa la información de búsqueda y asígnala a eventos específicos.

      INFORMACIÓN DE BÚSQUEDA:
      ${rawInfo}

      LISTA DE FUENTES DISPONIBLES (Úsalas para asignar el "sourceIndex"):
      ${groundingSources.map((s) => `[ID:${s.id}] ${s.title}: ${s.uri}`).join('\n')}

      REGLAS DE ORO:
      1. Para cada evento detectado, identifica cuál de las fuentes de la lista anterior (por su ID) es la que informa sobre ese suceso concreto.
      2. Asigna ese ID al campo "sourceIndex".
      3. Si el evento NO tiene una fuente específica en la lista anterior, usa "sourceIndex": -1.
      4. NUNCA inventes URLs ni asignes IDs de noticias que no tengan relación con el evento.
    `;

    const structResponse = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: structuringPrompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            events: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  title: { type: Type.STRING },
                  description: { type: Type.STRING },
                  severity: { type: Type.STRING, enum: ['CRITICAL', 'WARNING', 'INFO', 'SAFE'] },
                  category: { type: Type.STRING },
                  sourceName: { type: Type.STRING },
                  sourceIndex: { type: Type.INTEGER, description: "El ID de la fuente de la lista proporcionada" },
                  timeInfo: { type: Type.STRING }
                },
                required: ["title", "description", "severity", "category", "sourceName", "sourceIndex", "timeInfo"]
              }
            },
            riskAnalysis: { type: Type.STRING }
          },
          required: ["events", "riskAnalysis"]
        }
      }
    });

    const parsedData = JSON.parse(structResponse.text || '{"events":[], "riskAnalysis":""}');

    const events: AlertEvent[] = (parsedData.events || []).map((evt: any) => {
      const idString = `${evt.title}-${evt.timeInfo}-${location}`;
      let hash = 0;
      for (let i = 0; i < idString.length; i++) {
        hash = ((hash << 5) - hash) + idString.charCodeAt(i);
        hash |= 0;
      }

      // Recuperar la URL real usando el índice devuelto por la IA
      const sourceFromList = groundingSources.find(s => s.id === evt.sourceIndex);
      const finalUrl = sourceFromList ? sourceFromList.uri : "";

      const isOfficial = finalUrl.includes('112') || 
                        finalUrl.includes('gob.es') || 
                        finalUrl.includes('aemet.es') || 
                        finalUrl.includes('dgt.es') || 
                        finalUrl.includes('policia.es') || 
                        finalUrl.includes('guardiacivil.es') ||
                        evt.sourceName.toLowerCase().includes('112');

      return {
        id: `evt-${Math.abs(hash)}`,
        title: evt.title,
        description: evt.description,
        location: location,
        timestamp: evt.timeInfo,
        severity: evt.severity as SeverityLevel,
        category: evt.category,
        isHistorical: isHistorical,
        sources: [{
          name: evt.sourceName || (sourceFromList ? sourceFromList.title : "Fuente de información"),
          type: isOfficial ? SourceType.OFFICIAL : SourceType.NEWS,
          url: finalUrl
        }]
      };
    });

    return {
      events,
      analysis: parsedData.riskAnalysis || "Sincronización completada."
    };

  } catch (error) {
    console.error("fetchAlerts Critical Error:", error);
    return { events: [], analysis: "Error al verificar la integridad de los datos." };
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { 
  MapPin, Navigation, Search, History, AlertOctagon, RotateCw, Loader2, 
  Bell, BellOff, Sun, Moon, Info, ShieldAlert, Radio, ShieldCheck, Siren, 
  ArrowLeft, Clock, Activity 
} from 'lucide-react';
import { AlertEvent, UserLocation, SeverityLevel } from './types';
import { fetchAlerts } from './services/geminiService';
import { AudioService } from './services/audioService';
import AlertCard from './components/AlertCard';
import StatsChart from './components/StatsChart';

enum ViewState { ONBOARDING, DASHBOARD, HISTORY }

export default function App() {
  const [view, setView] = useState<ViewState>(ViewState.ONBOARDING);
  const [location, setLocation] = useState<UserLocation>({ name: '', isGPS: false });
  const [alerts, setAlerts] = useState<AlertEvent[]>([]);
  const [analysis, setAnalysis] = useState<string>('');
  const [loading, setLoading] = useState(false);
  const [radius, setRadius] = useState<number>(10);
  const [countdown, setCountdown] = useState(60);
  const [lastUpdate, setLastUpdate] = useState<string>('');
  const [permission, setPermission] = useState<NotificationPermission>('default');

  const [theme, setTheme] = useState<'light' | 'dark'>(() => {
    if (typeof window !== 'undefined') {
        const saved = localStorage.getItem('theme');
        return (saved === 'light' || saved === 'dark') ? saved : 'dark';
    }
    return 'dark';
  });

  useEffect(() => {
    const root = window.document.documentElement;
    if (theme === 'dark') root.classList.add('dark');
    else root.classList.remove('dark');
    localStorage.setItem('theme', theme);
  }, [theme]);

  useEffect(() => {
    if ('Notification' in window) setPermission(Notification.permission);
  }, []);

  const toggleTheme = () => setTheme(prev => prev === 'dark' ? 'light' : 'dark');

  const [historyDate, setHistoryDate] = useState<string>('');
  const [historyLocation, setHistoryLocation] = useState<string>('');
  const [formDay, setFormDay] = useState<number>(new Date().getDate());
  const [formMonth, setFormMonth] = useState<number>(new Date().getMonth());
  const [formYear, setFormYear] = useState<number>(new Date().getFullYear());
  const [formCategory, setFormCategory] = useState<string>('TODAS');

  const [isMonitoring, setIsMonitoring] = useState(false);

  useEffect(() => {
    if (view !== ViewState.DASHBOARD || historyDate || !isMonitoring || !location.name) {
      setCountdown(60);
      return;
    }
    const timer = setInterval(() => {
      setCountdown(prev => {
        if (prev <= 1) { refreshAlerts(); return 60; }
        return prev - 1;
      });
    }, 1000);
    return () => clearInterval(timer);
  }, [view, historyDate, isMonitoring, location.name]);

  const requestNotificationPermission = async () => {
    if (!('Notification' in window)) return;
    const result = await Notification.requestPermission();
    setPermission(result);
    if (result === 'granted') {
      setIsMonitoring(true);
      new Notification('Monitor Activado', { 
        body: `Rastreo activo para ${location.name}. Recibirás alertas críticas.`, 
        icon: 'https://cdn-icons-png.flaticon.com/512/564/564619.png' 
      });
    }
  };

  const toggleMonitoring = () => {
    if (isMonitoring) {
      setIsMonitoring(false);
    } else {
      if (permission === 'granted') {
        setIsMonitoring(true);
      } else {
        requestNotificationPermission();
      }
    }
  };

  const refreshAlerts = async () => {
    try {
      AudioService.playScan();
      const result = await fetchAlerts(location.name, undefined, radius);
      setAlerts(result.events);
      setAnalysis(result.analysis);
      setLastUpdate(new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', second: '2-digit' }));
      if (result.events.length > 0) AudioService.playSuccess();
    } catch (e) { console.error("Refresh error:", e); }
  };

  const handleGPSLocation = (target: 'current' | 'history') => {
    setLoading(true);
    AudioService.playScan();
    if ('geolocation' in navigator) {
      navigator.geolocation.getCurrentPosition(
        async (pos) => {
          const locName = `${pos.coords.latitude.toFixed(3)}, ${pos.coords.longitude.toFixed(3)}`;
          if (target === 'current') {
            setLocation({ lat: pos.coords.latitude, lng: pos.coords.longitude, name: `Cerca de ${locName}`, isGPS: true });
            await executeSearch(`Cerca de ${locName}`, undefined, radius);
          } else {
            setHistoryLocation(`Cerca de ${locName}`);
            setLoading(false);
            AudioService.playSuccess();
          }
        },
        () => { setLoading(false); alert("Error al obtener ubicación GPS. Introduce una ciudad manualmente."); }
      );
    } else {
        setLoading(false);
        alert("Geolocalización no soportada.");
    }
  };

  const executeSearch = async (locName: string, date?: string, searchRadius?: number, category?: string) => {
    setLoading(true);
    setCountdown(60);
    try {
      const result = await fetchAlerts(locName, date, searchRadius || radius, category);
      setAlerts(result.events);
      setAnalysis(result.analysis);
      setLastUpdate(new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }));

      // Solo actualizamos la ubicación principal si no es una búsqueda histórica
      if (!date) {
        setLocation(p => ({ ...p, name: locName }));
      }

      AudioService.playSuccess();
      setView(ViewState.DASHBOARD);
    } catch (e) { 
      alert("Error de conexión con la IA. Por favor, inténtalo de nuevo."); 
    } finally { 
      setLoading(false); 
    }
  };

  const handleManualLocation = (e: React.FormEvent) => {
    e.preventDefault();
    if (location.name.trim()) executeSearch(location.name);
  };

  const handleHistorySearch = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!historyLocation) return;
    const mm = (formMonth + 1).toString().padStart(2, '0');
    const dd = formDay.toString().padStart(2, '0');
