      <button onClick={toggleTheme} aria-label="Cambiar tema" className="absolute top-6 right-6 p-3 rounded-2xl bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 shadow-xl z-50 transition-transform active:scale-90">
        {theme === 'dark' ? <Sun className="w-5 h-5 text-yellow-500" /> : <Moon className="w-5 h-5 text-slate-700" />}
      </button>

      <div className="z-10 w-full max-w-md space-y-12 py-16 animate-in">
        <div className="flex flex-col items-center gap-8">
          <div className="relative">
             <div className="absolute inset-0 bg-blue-500/20 blur-3xl rounded-full scale-150 animate-pulse"></div>
             <div className="relative w-32 h-32 bg-white dark:bg-slate-900 rounded-[2.5rem] shadow-2xl border border-slate-100 dark:border-slate-800 flex items-center justify-center overflow-hidden">
                <ShieldAlert className="w-16 h-16 text-red-600 absolute z-10" />
                <div className="absolute inset-0 border-2 border-dashed border-slate-200 dark:border-slate-800 rounded-[2.5rem] animate-spin-slow opacity-50"></div>
                <Radio className="w-24 h-24 text-blue-500/10 animate-ping" />
             </div>
             <div className="absolute -bottom-2 -right-2 bg-emerald-500 p-2 rounded-xl shadow-lg border-4 border-white dark:border-slate-950">
                <ShieldCheck className="w-4 h-4 text-white" />
             </div>
          </div>
          <div className="text-center space-y-3">
             <h1 className="text-5xl font-black tracking-tight text-slate-900 dark:text-white uppercase leading-[0.9]">Monitor <br/> <span className="text-blue-600 dark:text-blue-500">España</span></h1>
             <p className="text-slate-400 dark:text-slate-500 font-bold uppercase tracking-[0.3em] text-[10px]">IA de Seguridad Pública</p>
          </div>
        </div>

        <div className="bg-white/90 dark:bg-slate-900/90 backdrop-blur-2xl p-8 rounded-[2.5rem] border border-slate-200 dark:border-slate-800 shadow-2xl space-y-8">
          <div className="space-y-4">
             <div className="flex justify-between text-[10px] font-black text-slate-400 uppercase tracking-widest px-1">
                <span>Rango de Análisis</span>
                <span className="text-blue-600 font-bold">{radius} KM</span>
             </div>
             <input type="range" min="5" max="100" step="5" value={radius} onChange={(e) => setRadius(Number(e.target.value))} className="w-full h-2 bg-slate-100 dark:bg-slate-800 rounded-full appearance-none accent-blue-600 cursor-pointer" />
          </div>

          <div className="grid gap-4">
            <button onClick={() => handleGPSLocation('current')} disabled={loading} className="w-full py-5 bg-slate-900 dark:bg-blue-600 hover:bg-slate-800 dark:hover:bg-blue-500 text-white rounded-2xl font-black flex items-center justify-center gap-3 transition-all active:scale-95 shadow-xl shadow-blue-500/10 uppercase tracking-widest text-sm disabled:opacity-50">
                {loading ? <Loader2 className="animate-spin w-5 h-5" /> : <Navigation className="w-5 h-5" />}
                Escanear Mi Posición
            </button>
            <form onSubmit={handleManualLocation} className="flex gap-2">
                <input type="text" placeholder="Buscar ciudad..." value={location.name} onChange={(e) => setLocation({ ...location, name: e.target.value })} className="flex-1 bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-800 rounded-2xl px-5 py-4 text-sm font-bold focus:ring-4 focus:ring-blue-500/10 outline-none transition-all" />
                <button type="submit" aria-label="Buscar" className="bg-blue-600 text-white p-4 rounded-2xl shadow-lg active:scale-90 transition-all">
                    <Search className="w-5 h-5" />
                </button>
            </form>
          </div>
          <button onClick={() => { AudioService.playScan(); setView(ViewState.HISTORY); }} className="w-full text-[10px] font-black text-slate-400 hover:text-blue-600 flex items-center justify-center gap-2 uppercase tracking-[0.2em] transition-colors">
            <History className="w-4 h-4" /> Consultar Archivo Histórico
          </button>
        </div>

        <div className="flex items-start gap-4 p-5 bg-white/50 dark:bg-slate-900/30 rounded-3xl border border-slate-200/50 dark:border-slate-800/50">
            <div className="p-2 bg-blue-500/10 rounded-xl"><Info className="w-5 h-5 text-blue-500" /></div>
            <p className="text-[11px] text-slate-500 dark:text-slate-400 leading-relaxed font-medium">
                Monitoriza alertas de <strong>AEMET, DGT y 112</strong> en tiempo real. Esta herramienta no es oficial. En caso de peligro inmediato, llame al 112.
            </p>
        </div>
      </div>
    </div>
  );

  return (
    <div className="h-screen bg-slate-50 dark:bg-slate-950 font-sans selection:bg-blue-500 selection:text-white">
      {view === ViewState.ONBOARDING && renderOnboarding()}
      {view === ViewState.HISTORY && (
        <div className="h-screen p-6 bg-grid overflow-y-auto relative">
            <button onClick={() => setView(ViewState.ONBOARDING)} className="absolute top-6 left-6 p-3 rounded-2xl bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 shadow-xl z-50 flex items-center gap-2 text-xs font-bold uppercase text-slate-500 transition-all hover:text-blue-600">
                <ArrowLeft className="w-4 h-4" /> Volver
            </button>
            <div className="max-w-md mx-auto py-24 space-y-12 animate-in">
                <div className="text-center space-y-2">
                    <Clock className="w-12 h-12 mx-auto text-purple-600 mb-4" />
                    <h2 className="text-4xl font-black uppercase tracking-tighter italic text-slate-900 dark:text-white leading-none">Cápsula <br/> del Tiempo</h2>
                    <p className="text-[10px] font-black text-purple-500 uppercase tracking-[0.2em]">Recuperación de Datos Históricos</p>
                </div>
                <div className="bg-white/90 dark:bg-slate-900/90 backdrop-blur-2xl p-8 rounded-[2.5rem] border border-slate-200 dark:border-slate-800 shadow-2xl">
                    <form onSubmit={handleHistorySearch} className="space-y-6">
                        <div className="space-y-2">
                           <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-1">Ubicación para Archivo</label>
                           <div className="flex gap-2">
                              <input type="text" required placeholder="Ej: Valencia..." value={historyLocation} onChange={(e) => setHistoryLocation(e.target.value)} className="flex-1 bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-800 rounded-2xl px-5 py-4 text-sm font-bold outline-none" />
                              <button type="button" onClick={() => handleGPSLocation('history')} disabled={loading} className="bg-purple-500/10 text-purple-500 p-4 rounded-2xl border border-purple-500/20 hover:bg-purple-500/20 transition-all active:scale-90 shadow-sm">
                                {loading ? <Loader2 className="w-5 h-5 animate-spin" /> : <Navigation className="w-5 h-5" />}
                              </button>
                           </div>
                           <p className="text-[8px] text-slate-400 uppercase tracking-wider px-2">Puedes usar tu GPS actual o escribir una ciudad</p>
                        </div>
                        <div className="space-y-2">
                            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-1 text-center block">Fecha de Registro</label>
                            <div className="grid grid-cols-3 gap-2">
                                <select value={formDay} onChange={(e) => setFormDay(Number(e.target.value))} className="bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-800 rounded-xl py-3 text-xs font-bold text-center appearance-none">{Array.from({length: 31}, (_, i) => <option key={i+1} value={i+1}>{i+1}</option>)}</select>
