            </button>
            <form onSubmit={handleManualLocation} className="flex gap-2">
                <input type="text" placeholder="Ciudad..." value={location.name} onChange={(e) => setLocation({ ...location, name: e.target.value })} className="flex-1 bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-800 rounded-2xl px-5 py-3.5 text-xs font-bold focus:ring-4 focus:ring-blue-500/10 outline-none transition-all" />
                <button type="submit" aria-label="Buscar" className="bg-blue-600 text-white p-3.5 rounded-2xl shadow-lg active:scale-90 transition-all">
